INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (14022, 0, 0, 'The best way to this daily questline (if you wanna do them al the 7 days): Doesn\'t matter where you start. Where ever you start buy 20 potatoes (Dar), 20 cranberries (IF), or 20 pumpkins (SW). The first day you have to go every place.... but then you will have 20 of everything in your bags and you get the quest, make the pie, chutney, or sweet potatoes... and off you go. If you are in SW, do not forget to hunt for 20 turkeys when you are there, because in IF they want 20 cooked ones... It takes 10 minutes like this... instate of the 40 minutes first day i did it. var lv_screenshots = [{\"id\":1202193,\"user\":\"auryunderground\",\"date\":\"2024-11-24T14:18:07-06:00\",\"width\":989,\"height\":806,\"type\":5,\"typeId\":14022,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":291895,\"user\":\"gtulgar1903\",\"date\":\"2023-11-20T19:21:30-06:00\",\"videoType\":1,\"videoId\":\"0tPeMXRw1YA\",\"type\":5,\"typeId\":14022,\"url\":null,\"caption\":\"Pilgrim\'s Bounty! Wow Quest | Pilgrim\'s Bounty Event | Alliance\",\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":14022,\"name\":\"Pilgrim\'s Bounty\"}; WH.Layout.set({breadcrumb: [0, 3, 9, -1008]}); //]]> // Links Pilgrim\'s Bounty Speak with Gregory Tabor just outside the city gates of Stormwind. {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has 