INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (14036, 0, 0, 'If you\'ve ever wanted to level your cooking but were put off by farming tons of mats, now\'s your chance. The You can raise your cooking from 0 - 355 by cooking the recipes contained in Bountiful Cookbook . The only thing you\'ll have to farm are turkeys, which are very easy to hunt down.', 0);
