INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (29400, 0, 0, 'This quest is bugged if you take the portal from Orgrimmar. It teleports you to an Undercity that has a plague that will kill you. Tickets have been put in from what I read during some research. I tried taking the boat from Ratchet to STV and then flying up but it still killed me when I got there so don\'t bother trying.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (29415, 0, 0, 'As of the last patch of SL (Halloween 2022), this quest is phased out in Orgrimmar. You\'ll need to party sync to even see the quest. The quest giver is still there, but without the (!). As long as you haven\'t done the SL storyline, I believe you\'ll be in the correct version of Orgrimmar. If not, you\'ll need to either do it on a lower toon or party sync it up. My guess is someone forgot to add this quest to the latest phase because it\'s only around for a few days a year.', 0);
