INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (31312, 0, 0, 'I am reminded of the Grateful Dead\'s songs Franklin\'s Tower and Terrapin Station when reading this quest text. &quot;Deep in the valley where the four winds blow&quot; from the quest compared to &quot;May the four winds blow you safely home&quot; in Franklin\'s Tower. &quot;The maiden laughs behind her golden fan&quot; in the quest and &quot;(The Lady) takes her fan and throws it in the lion\'s den&quot; from Terrapin Station. This isn\'t the first time we had something resembling Grateful Dead lyrics in the game so i wouldn\'t be surprised if this is a subtle reference :)', 0);
