INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (31856, 0, 0, 'Not being able to do this quest in Legion Remix does not prevent you from completing your Order Campaign. Just finish this some other time I guess. var lv_screenshots = []; var lv_videos = [{\"id\":86896,\"user\":\"WoWQHelps\",\"date\":\"2015-09-19T10:40:26-05:00\",\"videoType\":1,\"videoId\":\"yri0u8win3E\",\"type\":5,\"typeId\":31856,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":31856,\"name\":\"The Peak of Serenity - Begin Your Training\"}; WH.Layout.set({breadcrumb: [0, 3, 4, -395]}); //]]> // Links The Peak of Serenity - Begin Your Training Use Zen Pilgrimage to travel to the Peak of Serenity. Speak to Master Hight in the Shrine of the Ox when you arrive. {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
