INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (32009, 0, 0, 'Lok\'tar, &lt;name&gt;. My name is Varzok . I have heard much your accomplishments as a tamer recently, and I would like to introduce you to trainers around Azeroth so that you may further hone your skills. Please speak with me in Orgrimmar so that we may begin.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (32040, 0, 0, 'I\'ve done the kun-lai quests but when I try to get this final candy bucket there\'s a bunch of max-level Mogu everywhere and I don\'t know how to unphase them. var lv_screenshots = [{\"id\":671534,\"user\":\"Whiterock\",\"date\":\"2017-10-29T12:10:43-05:00\",\"width\":904,\"height\":1200,\"type\":5,\"typeId\":32040,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":286626,\"user\":\"gtulgar1903\",\"date\":\"2023-10-22T22:07:00-05:00\",\"videoType\":1,\"videoId\":\"Xcsf2-ClJf0\",\"type\":5,\"typeId\":32040,\"url\":null,\"caption\":\"Tricks and Treats of Pandaria Achievement | How To Unlock Eastwind Rest | Horde | Hallow\'s End Event\",\"sticky\":1},{\"id\":393743,\"user\":\"vitorlambertucci\",\"date\":\"2025-12-02T12:10:18-06:00\",\"videoType\":1,\"videoId\":\"kHbrQ-X1wi0\",\"type\":5,\"typeId\":32040,\"url\":null}]; var g_pageInfo = {\"type\":5,\"typeId\":32040,\"name\":\"Candy Bucket\"}; WH.Layout.set({breadcrumb: [0, 3, 9, -1003]}); //]]> // Links Candy Bucket', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (32974, 0, 0, 'Question! So I haven\'t seen it mentioned, yet, but I am wondering and wanting to know if this quest is repeatable? Maybe a weekly thing like some of the Treasure Boxes. Any one who might be able to confirm doing this quest line at least twice on the same player?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (34067, 0, 0, 'I\'m growing tired of waiting, do you have anything to help our assault or not?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (35236, 0, 0, 'Couple of things of note, from the point of view of an alliance mage, L96, quest greens/blues: The Bonus Objective stuff popped onto my Quest Objective panel when I got to the area of Ra\'tok the Hammer , coming downhill from where you\'re supposed to be destroying siege weapons Iron Them Out (and killing the one called Dreadpiston ). I found this because, when I died, the nearest graveyard put me over the river, and I had to run back around along the coast to find the road up to the top of the cliff, because the thing that looks like a road across the river is a high bridge, and the bonus objective showed up when I was a corpse. This is NOT where the bulk of the Iron Shredder s, and any lumber, are found. *That* is further north/westish along the coast - and where the \'blue blob\' on the minimap shows. There is *one* Iron Shredder near Ra\'tok the Hammer , perhaps as a breadcrumb. There are also bunches of orcs landing in Iron Boats (which show up when you mouse over them, and are hostile. o.O ). They *will* jump you when you\'re busy killing shredders, which hit hard for how many hit points they have. If you run closer to the cliff, along that edge of the blue blot on the minimap, you will have the shredders between you and the landing orcs, and are less likely to get jumped. These orcs *do* count for Vol. X Pages ? . I had to look a lot farther than just around the 6 shredders I had to kill, for the lumber. And I found it far, far easier to hearth back to my garrison, and then fly back to Redemption Rise, than to make my way back past the shredders, the landing orcs, Ra\'tok, and all the orcs between me and the siege engines I still needed to destroy. var lv_screenshots = [{\"id\":1156208,\"user\":\"Rantsi\",\"date\":\"2024-04-13T12:38:55-05:00\",\"width\":1600,\"height\":900,\"type\":5,\"typeId\":35236,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":35236,\"name\":\"Orunai Coast\"}; WH.Layout.set({breadcrumb: [0, 3, 13, 6662]}); //]]> // Links Orunai Coast &nbsp; Iron Shredder slain &nbsp;( 6 ) Lumber &nbsp;( 20 ) WH.ge(\'icon-list-icon1\').appendChild(g_items.createIcon(112994, 0, 20, null, null)); {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
