INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (35974, 0, 0, 'Filing my tax return was more fun than this.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (35977, 0, 0, 'So it appears that only medium sized eggs and larger, count toward the quest as well as Darktide NPC\'s. There is one really large egg on the east side of the island. I would say it accounts for about 5% of the quest.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36069, 0, 0, 'Assault on Skettis is a possible daily quest offered by your Garrison for 800 Apexis Crystals . I have only found one way into the mountains where Skettis is, and it goes through Gordal Fortress, where there is a purple and blue fire wall keeping you out until you progress through Talador\'s questing. All area\'s on the map that show water are gated through waterfalls.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36070, 0, 0, 'The easiest way to get to the area of the quest is to take the flight path to Akeeta\'s Hovel in Shadowmoon Valley. Once there, take the road going North which leads you straight in to the quest area. Once in the area the usual &quot;fill it up bar&quot; shows up on your screen. There\'s an Outcast Darkscryer w/ a chat bubble over his head, inside a sort of shadow bubble. If you click to talk to him he just tells you what you have to do to complete the mission. &quot;Free the outcasts, lead them in battle, escort them out to the Darkscryers, don\'t let them perish. Got it.&quot; Basically just kill the NPC\'s in the area, loot Talon Keys from them and free the trapped Arakkoa Outcasts by clicking on the chain balls. You\'ll get a buff, Free Arakkoa Outcast , that lasts 5 mins and the NPC will follow you around and fight with you. You can only have 4 of the outcasts following you at a time. So kill the NPCs until you have 4 keys, free 4 outcasts. Kill more NPCs, keeping an eye on your follower timers. The bar on the screen fills up as you fight, it\'s the morale of your current followers. Fight until the timer gets low then take them over to the Outcast Darkscryer and click to talk to him. Turn them in to him and by this time you should have 4 more keys. Just rinse and repeat until the quest completes. Progress was shown by a blue bar in the Objectives pane. It fills up as you kill the bad guys and turn in the freed Arakkoa Outcasts . The higher the morale when you turn them in the more progress is made. Happy questing! Just to be a little clearer in the explanation, the bar that fills up at the bottom of your screen will only start to fill once you have freed at least 1 of the Arakkoa Outcasts and then start killing the other NPCs. It fills up faster the more outcasts you have following you, to a max of 4, and the more NPCs you kill. This bar is showing you the morale of the Outcasts currently following you and will reset to 0 when you turn those followers in to the Outcast Darkscryer . It does NOT show quest progress, that is shown on the bar under the Quest Objectives list. Of course, I wasn\'t using any UI or quest addons so that may be different if you are. speakersfankey made a comment that I believe should be added here so that it\'s more visible: &quot;To speed things up loot the yellow glowing eggs as well as artifacts scattered around, activate the yellow anima machines if you can find them and kill the non-energized birds with low hp.&quot; edited for clarity added speakersfankey\'s advice', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36080, 0, 0, 'This scale is proof of your strength at slaying ogron and your gladiator friend has born witness! Take the scale back to Limbflayer and claim your accolades!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36119, 0, 0, 'as you enter Ashran, don\'t accept queue. Simply ride to the npc to turn it in var lv_screenshots = [{\"id\":437150,\"user\":\"Rantsi\",\"date\":\"2014-11-19T15:46:41-06:00\",\"width\":1776,\"height\":999,\"type\":5,\"typeId\":36119,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":36119,\"name\":\"Welcome to Ashran\"}; WH.Layout.set({breadcrumb: [0, 3, 13, 7332]}); //]]> // Links Welcome to Ashran This quest was marked obsolete by Blizzard and cannot be obtained or completed.', 0);
