INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36347, 0, 0, 'Assault on Socrethar\'s Rise https://www.youtube.com/watch?v=l0cdlB-q6Fo Achievements: A Demidos of Reality achievement video http://youtu.be/4QwbJzI-Zho If you can\'t climb up, here is the easiest rock. At least it was for me: http://youtu.be/zMT9u18u2pk Demidos can drop Servant of Demidos . 1-st kill gives you A Demidos of Reality achievement. Take From Them Everything using fruit baskets around 50, 73 in the North-East Corner https://www.youtube.com/watch?v=mEHDb4r8UpM It\'s the Stones! achievement video https://www.youtube.com/watch?v=2iXus6vpF30 Draenic Darkstone locations : 49.5, 71.2 behind the pumpkin farm https://www.youtube.com/watch?v=0vtEa-0DuW0 47.4, 76.4 on top of the rock https://www.youtube.com/watch?v=92Szh4xLTlU 47.5, 78.5 on top of the rock https://www.youtube.com/watch?v=hIAIf9qiStA 52.6, 80.4 near the cliff https://www.youtube.com/watch?v=JENzC9Vdbg8 46.5, 71.6 near Demidos rare https://www.youtube.com/watch?v=ux8kjgeo6D4 If the area is crowded try to switch to low populated servers via LFG Rares: Demidos 46.0, 71.8 http://youtu.be/4QwbJzI-Zho Master Sergeant Milgra 51.8, 79.0 http://youtu.be/eQ_n9s9A7CU Lady Temptessa 48.2, 77.6 http://youtu.be/g3JwzokDD6Y Aqualir 51.0, 79.0 http://youtu.be/88U3aeu14_8 Shadowspeaker Niir 48.2, 80.8 http://youtu.be/y1Di-rDXP58 Quartermaster Hershak 50.2, 72.6 http://youtu.be/7wznNJc9emQ Assault invasion: Shadowmoon Invasion!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36348, 0, 0, 'Achievements linked to this daily; It\'s the Stones! Take From Them Everything (Don\'t need the daily for this though) A Demidos of Reality Part of Securing Draenor', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36383, 0, 0, 'You get this quest in your Garrison\'s Town Hall, at the War Map, which is on a table, and has a blue daily exclamation point. Fly to as far north and west in Gorgrond as you can get. There is a Flight Master at Iron Docks, pick this flight path up. When you get there join a standard group of five: tank, healer, three DPS. Use Group Finder, Premade Groups, Find Group, and Quests. There will be many groups.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36429, 0, 0, 'I compiled a list of waypoints from previous user comments. Thank you all for sharing them. /way Spires of Arak 54.90, 79.74 /way Nagrand:Draenor 58.97, 38.44 /way Nagrand:Draenor 56,70 /way Talador 59, 29 /way Talador 73, 28 /way Shadowmoon Valley:Draenor 46, 31.5 /way Gorgrond 45.53, 66.3 var lv_screenshots = [{\"id\":442957,\"user\":\"Mikimo\",\"date\":\"2014-12-06T16:09:55-06:00\",\"width\":1920,\"height\":1080,\"type\":5,\"typeId\":36429,\"imageType\":2,\"staffOnly\":false,\"caption\":\"This is logation where i found it, just click tree and follower spawn give quest, Tomtom coordinates \\/way Talador 73.7, 64.0 Weldon Barov (Fallen Tree - Requires Lumber Mill - Be Patient)\",\"sticky\":1},{\"id\":508869,\"user\":\"xSylvane\",\"date\":\"2016-03-21T23:42:53-05:00\",\"width\":1920,\"height\":1018,\"type\":5,\"typeId\":36429,\"imageType\":2,\"staffOnly\":false}]; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":36429,\"name\":\"The Rise and Fall of Barov Industries: Weldon Barov\"}; WH.Layout.set({breadcrumb: [0, 3, 13, 6720]}); //]]> // Links The Rise and Fall of Barov Industries: Weldon Barov Accept the Blood Oath of Blademaster Na\'Shra.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36489, 0, 0, 'There is a bar at the bottom of your screen that fills up with the killing of mobs in the area. Fill the bar (like the bar on some Cata or MoP raid encounters - Sha of Pride as a recent example) and you complete the quest. As Mouzi said, if you spot a rare, your group should head out to it. Currently, there are a lot of people working this quest for crystals (you need just under 5k for the Legendary ring questline) so dont sell yourself short by going in less than 5. Typical 5 man party should work as there\'s a lot of dmg that goes out.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36490, 0, 0, 'Shadowmoon Enclave in Spires of Arak: Assault on Pillars of Fate or Assault on Pillars of Fate There are several void portals, but, i think, (72.27 23.62) is the closest to rares. Here is portal location video: http://youtu.be/ceqJilhT-Bw Achievements A-VOID-ance | http://youtu.be/jjoI17bpw5A Enter void portal. Need 3 ppl to summon rare. Keep away from adds with debuff Devouring Void . One of Us! One of Us! | http://youtu.be/j6ice2whScw Enter void portal. Kill mobs. Would You Like a Pamphlet? | http://youtu.be/H30GFP8SNeg Collect Forbidden Tomes /way 74.62 31.22 /way 74.27 27.73 /way 74.6 31.2 /way 72.76 32.50 /way 71.7 27.9 /way 70.51 24.15 /way 69.73 20.0 Rares Kenos the Unraveler (70.6, 24.2) Void World http://youtu.be/jjoI17bpw5A | 3 ppl to summon Formless Nightmare (72.6, 19.6) Void World http://youtu.be/HfZOSttuWPQ Soul-Twister Torek (72.6, 19.6) http://youtu.be/IicPuxflHng Can drop Black Whirlwind Voidreaver Urnae (74.0, 32.4) http://youtu.be/0nLj3EPO5Vc ... probably there can be more, but i can\'t find them on wowhead. Will give GarInvasion_Shadowmoon reputation for Shadowmoon Invasion! Garrison Invasions', 0);
