INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36649, 0, 0, 'Did they disable this quest? I did it a few times as a fresh 100 and after I started to get heroic gear I only got the west side of Shattrath where the residential area is as a daily quest. The harbor has a lot more interactive stuff, like the mortar launchers and the dead bodies floating in the water that you can use to get a few easy % in between pulls.', 0);
