INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36674, 0, 0, 'Driving me mad on EU Azjol waiting for this one .. not seen it once.. last one required for the meta. Update on this - still waiting , reportedly it showed up on dec 25th (Of course the one day since launch I\'ve not been on) But absolutely no sign since. and still we wait x.x', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36676, 0, 0, 'Fly to Everbloom Wilds, Gorgrond (56,45). The daily is right in front of the flight path. Kill stuff, throw rocks at birds in trees.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36677, 0, 0, 'Never got my Apexis crystal rewards when completing this. Not sure if anyone else has had this issue.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36678, 0, 0, 'Located in center-west Nagrand, you will be fighting stuff like Mok\'gol Grunt to complete this quest. Look for stakes in the ground and bombs beside the buildings that you can destroy, steal their precious treasure chests and just wreak havoc. The coils of rope are to help you climb up and down the towers, within which you will find 3 defenders and potentially a treasure chest. Blowing up buildings seems to give the biggest completion boost. There are several hidden objects throughout the village, one of which turns you into a spectral wolf - I believe this might have something to do with the mounds of soil, but am uncertain on that one. The achievement is Buried Treasures and the very first post confirms this suspicion with a little more detail.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36679, 0, 0, 'Filing my tax return was more fun than this.', 0);
