INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36682, 0, 0, 'Shadowmoon Enclave in Spires of Arak: Assault on Pillars of Fate or Assault on Pillars of Fate There are several void portals, but, i think, (72.27 23.62) is the closest to rares. Here is portal location video: http://youtu.be/ceqJilhT-Bw Achievements A-VOID-ance | http://youtu.be/jjoI17bpw5A Enter void portal. Need 3 ppl to summon rare. Keep away from adds with debuff Devouring Void . One of Us! One of Us! | http://youtu.be/j6ice2whScw Enter void portal. Kill mobs. Would You Like a Pamphlet? | http://youtu.be/H30GFP8SNeg Collect Forbidden Tomes /way 74.62 31.22 /way 74.27 27.73 /way 74.6 31.2 /way 72.76 32.50 /way 71.7 27.9 /way 70.51 24.15 /way 69.73 20.0 Rares Kenos the Unraveler (70.6, 24.2) Void World http://youtu.be/jjoI17bpw5A | 3 ppl to summon Formless Nightmare (72.6, 19.6) Void World http://youtu.be/HfZOSttuWPQ Soul-Twister Torek (72.6, 19.6) http://youtu.be/IicPuxflHng Can drop Black Whirlwind Voidreaver Urnae (74.0, 32.4) http://youtu.be/0nLj3EPO5Vc ... probably there can be more, but i can\'t find them on wowhead. Will give GarInvasion_Shadowmoon reputation for Shadowmoon Invasion! Garrison Invasions', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36683, 0, 0, 'Assault on Skettis is a possible daily quest offered by your Garrison for 800 Apexis Crystals . I have only found one way into the mountains where Skettis is, and it goes through Gordal Fortress, where there is a purple and blue fire wall keeping you out until you progress through Talador\'s questing. All area\'s on the map that show water are gated through waterfalls.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36684, 0, 0, 'Just as a warning. Don\'t pick this quest if you are easily frustrated. Every time you are killed by Horde the number of fragments you have are halved. I assume the player that loot your body gets them. I think the best bet to get them is farming the mobs in the areas off the side of the main road.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36685, 0, 0, 'If you want to do this group daily by yourself, there\'s a platform at 36, 42 (up some stairs, greenhouse on each side, stairs at the back that lead down) which has discrete packs of mobs (go down the back stairs to find more) along with some posters to burn and scrolls to loot. It\'s not the fastest, but it\'s pretty safe from overpulling and as you kill the last of the packs downstairs the ones up top will generally have respawned.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36689, 0, 0, 'The quest seems bugged for me. I\'m not getting a progress bar. Solved it with a relog, good to know. Abandon and retake quest didn\'t help.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36690, 0, 0, 'I just managed to die while on this quest, and the Amorphic Cognitor simply left my brain, and whispered &quot;We have chosen... poorly. We will find another host.&quot; The quest is no longer in my quest log. No actual notification of failure whatsoever. Is that normal?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36691, 0, 0, 'Assault on Socrethar\'s Rise https://www.youtube.com/watch?v=l0cdlB-q6Fo Achievements: A Demidos of Reality achievement video http://youtu.be/4QwbJzI-Zho If you can\'t climb up, here is the easiest rock. At least it was for me: http://youtu.be/zMT9u18u2pk Demidos can drop Servant of Demidos . 1-st kill gives you A Demidos of Reality achievement. Take From Them Everything using fruit baskets around 50, 73 in the North-East Corner https://www.youtube.com/watch?v=mEHDb4r8UpM It\'s the Stones! achievement video https://www.youtube.com/watch?v=2iXus6vpF30 Draenic Darkstone locations : 49.5, 71.2 behind the pumpkin farm https://www.youtube.com/watch?v=0vtEa-0DuW0 47.4, 76.4 on top of the rock https://www.youtube.com/watch?v=92Szh4xLTlU 47.5, 78.5 on top of the rock https://www.youtube.com/watch?v=hIAIf9qiStA 52.6, 80.4 near the cliff https://www.youtube.com/watch?v=JENzC9Vdbg8 46.5, 71.6 near Demidos rare https://www.youtube.com/watch?v=ux8kjgeo6D4 If the area is crowded try to switch to low populated servers via LFG Rares: Demidos 46.0, 71.8 http://youtu.be/4QwbJzI-Zho Master Sergeant Milgra 51.8, 79.0 http://youtu.be/eQ_n9s9A7CU Lady Temptessa 48.2, 77.6 http://youtu.be/g3JwzokDD6Y Aqualir 51.0, 79.0 http://youtu.be/88U3aeu14_8 Shadowspeaker Niir 48.2, 80.8 http://youtu.be/y1Di-rDXP58 Quartermaster Hershak 50.2, 72.6 http://youtu.be/7wznNJc9emQ Assault invasion: Shadowmoon Invasion!', 0);
