INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36693, 0, 0, 'Assault on Mok\'gol Watchpost http://www.youtube.com/watch?v=KUaJNqEWdoU', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36694, 0, 0, 'Massive ogron have been battering our frontlines, and no matter how many we down, there seem to be more to replace them. Most of these ogron appear to be coming from the Broken Precipice , deep in western Nagrand. If we\'re to stand a chance in the coming battles, we need to find a way to remove these ogron from the battlefield.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36695, 0, 0, 'Location : Quest credit is granted in a large area of northeast Gorgrond. The southwestern area begins around flightmaster Arcanist Windlebop by the entrance to The Everbloom and curves up to flightmaster Researcher Sarix and then down again along the eastern coast. Rewards : 0 Apexis Crystal Related achievements : Ancient No More , Burn It to the Ground , Mean and Green , Picky Palate , Pillars of Draenor Related Reputation : Laughing Skull Orcs Related Garrison Invasion : Botani Invasion! Related Loot : Depthroot\'s Forearm from Depthroot , Botani Camouflage and Grovetender\'s Cummerbund from Basten , Hydratooth Dagger from Venolasix , Grash\'s Fireproof Handguards from Firestarter Grash , Thorn-Knuckled Gloves from Alkali , Flayerscale Carapace Stompers from Swift Onyx Flayer , Yal\'s Leafwrap Cloak from Grove Warden Yal , Etched Osteoderm Shield from Mogamago , Bal\'ra\'s Compound Bow from Hunter Bal\'ra', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36696, 0, 0, 'Just did the achievements, both for keg and plans and you don\'t even need to look for 10 of each, find 1 and spam click ( cancelling the loading ) and it makes it count towards the achievement without even destroying it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36697, 0, 0, 'I made i playthrough of this quest if anyone wish to see how to do it :) https://www.youtube.com/watch?v=DlJS1Dr5Mjk', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36698, 0, 0, 'Now u need 100 fragments to turn in at garrison.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36808, 0, 0, 'Did they disable this quest? I did it a few times as a fresh 100 and after I started to get heroic gear I only got the west side of Shattrath where the residential area is as a daily quest. The harbor has a lot more interactive stuff, like the mortar launchers and the dead bodies floating in the water that you can use to get a few easy % in between pulls.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36814, 0, 0, 'Location : Quest credit is granted in a large area of northeast Gorgrond. The southwestern area begins around flightmaster Arcanist Windlebop by the entrance to The Everbloom and curves up to flightmaster Researcher Sarix and then down again along the eastern coast. Rewards : 0 Apexis Crystal Related achievements : Ancient No More , Burn It to the Ground , Mean and Green , Picky Palate , Pillars of Draenor Related Reputation : Laughing Skull Orcs Related Garrison Invasion : Botani Invasion! Related Loot : Depthroot\'s Forearm from Depthroot , Botani Camouflage and Grovetender\'s Cummerbund from Basten , Hydratooth Dagger from Venolasix , Grash\'s Fireproof Handguards from Firestarter Grash , Thorn-Knuckled Gloves from Alkali , Flayerscale Carapace Stompers from Swift Onyx Flayer , Yal\'s Leafwrap Cloak from Grove Warden Yal , Etched Osteoderm Shield from Mogamago , Bal\'ra\'s Compound Bow from Hunter Bal\'ra', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36815, 0, 0, 'Achievements linked to this daily: Picky Palate Ancient No More (Don\'t know if you can do this without the daily) Burn it to the Ground Mean and Green Pillars of Draenor Part of Securing Draenor', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36816, 0, 0, 'Never got my Apexis crystal rewards when completing this. Not sure if anyone else has had this issue.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36817, 0, 0, '[PH]Commander! You just missed a group of rangari with some disturbing news. The Shadowmoon Orcs have been spotted in the hills above Anguish Fortress. The scouts reported seeing strange rituals and beings of pure darkness. Those orcs must be up there trying to summon more minions from the Void! If we do not intervene all we have gained in Shadowmoon Valley might be lost! See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(36817)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(36817))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36818, 0, 0, 'Located in center-west Nagrand, you will be fighting stuff like Mok\'gol Grunt to complete this quest. Look for stakes in the ground and bombs beside the buildings that you can destroy, steal their precious treasure chests and just wreak havoc. The coils of rope are to help you climb up and down the towers, within which you will find 3 defenders and potentially a treasure chest. Blowing up buildings seems to give the biggest completion boost. There are several hidden objects throughout the village, one of which turns you into a spectral wolf - I believe this might have something to do with the mounds of soil, but am uncertain on that one. The achievement is Buried Treasures and the very first post confirms this suspicion with a little more detail.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36819, 0, 0, 'Assault on Mok\'gol Watchpost http://www.youtube.com/watch?v=KUaJNqEWdoU', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36822, 0, 0, 'Driving me mad on EU Azjol waiting for this one .. not seen it once.. last one required for the meta. Update on this - still waiting , reportedly it showed up on dec 25th (Of course the one day since launch I\'ve not been on) But absolutely no sign since. and still we wait x.x', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36823, 0, 0, 'Sometimes WoW drives me absolutely bat-&amp;*!@, smash everything-in-sight, scream my lungs out, #$%^ing crazy! Why? Because I\'ve just wasted an hour trying to find out where to pick up this questline! Simple, eh? Well why doesn\'t wowhead bother to mention it?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36826, 0, 0, 'You can find pillaged caravan goods scattered around the area to speed up the progress bar, you can also find and click earthen spikes that have fire elementals trapped inside them to speed up the bar. and as someone else here said you can click on acidmaw eggs to speed up the progress bar, the eggs are in the lava pits. the guys rolling around can be rolled into elites to make them take 50% more damage but it is still the longer way.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36827, 0, 0, 'To find the entrance to Magnarok- When you approach Magnarok there will be an on-screen notification that you have enter the area known as Gate of Breakers . You will find a bleached skeleton of a dead beast. Go beyond the skeleton and look to the east to find the cave mentioned by others. A faster way is to use the snowy slope to the left of the cave. There are Rolling Shardbacks and Ravenous Ironchewers rolling up and down that same slope. Go up the slope and you are have arrived. There are opportunities to complete a daily and an assault along with battling two bosses. Have fun. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":36827,\"name\":\"Assault on Magnarok\"}; WH.Layout.set({breadcrumb: [0, 3, 26, -403]}); //]]> // Links Assault on Magnarok &nbsp; Magnarok Assaulted &nbsp;( 1 ) &nbsp; Minus Mobs Killed &nbsp;(500) &nbsp; Acidmaw Nibbler &nbsp;( 1 ) &nbsp; Kill Credit (Magnarok - Minus) &nbsp;( 1 ) &nbsp; Mind-Frozen Rockbiter &nbsp;( 1 ) &nbsp; Slagmaw Nibbler &nbsp;( 1 ) &nbsp; Acidmaw Nibbler &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Normal Mobs Killed &nbsp;(100) &nbsp; Icejaw Rockbiter &nbsp;( 1 ) &nbsp; Coalesced Rune Magma &nbsp;( 1 ) &nbsp; Kill Credit (Magnarok - Normal) &nbsp;( 1 ) &nbsp; Burning Slagmaw &nbsp;( 1 ) &nbsp; Burning Slagmaw &nbsp;( 1 ) &nbsp; Howling Icefury &nbsp;( 1 ) &nbsp; Burning Slagmaw &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; High HP Normal Mobs Killed &nbsp;(50) &nbsp; Icejaw Rockbiter &nbsp;( 1 ) &nbsp; Coalesced Rune Magma &nbsp;( 1 ) &nbsp; Kill Credit (Magnarok - Normal) &nbsp;( 1 ) &nbsp; Burning Slagmaw &nbsp;( 1 ) &nbsp; Burning Slagmaw &nbsp;( 1 ) &nbsp; Howling Icefury &nbsp;( 1 ) &nbsp; Burning Slagmaw &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Collect (Minor) &nbsp;( 1000 ) &nbsp; Elite Killed &nbsp;(25) &nbsp; Icecrag Mountainbreaker &nbsp;( 1 ) &nbsp; Kill Credit (Magnarok - Elite) &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Miniboss/Event Killed &nbsp;(7) &nbsp; Gorg\'ak the Lava Guzzler &nbsp;( 1 ) &nbsp; Hoarfrost &nbsp;( 1 ) &nbsp; Mother of Goren &nbsp;( 1 ) &nbsp; Kill Credit (Magnarok - Rare Elite/Event/Miniboss) &nbsp;( 1 ) &nbsp; The Bone Crawler &nbsp;( 1 ) &nbsp; Gomtar the Agile &nbsp;( 1 ) &nbsp; Gibblette the Cowardly &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; 5man Boss Killed &nbsp;(5) &nbsp; Vrok the Ancient &nbsp;( 1 ) &nbsp; Valkor &nbsp;( 1 ) &nbsp; Kill Credit (Magnarok - 5man Boss) &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Collect &nbsp;( 50 ) &nbsp; Cragstomper &nbsp;(34) &nbsp; Vicious Acidmaw &nbsp;( 1 ) &nbsp; Frostfire Cragstomper &nbsp;( 1 ) &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} // See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(36827)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(36827))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (36840, 0, 0, 'Place another work order with my assistant. Once it is complete, we will leave it out here for you to collect.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37184, 0, 0, 'Could not find the quest \'Taking the flight to Nagrand\' But it let me start this quest series in Nagrand \'The Might of the Warsong\' just north of MAR\'GOK\'S OVERWATCH by the road. According to my addon QUEST COMPLETIST im not done with this quest yet so I\'m not sure what is going on here. Maybe because I started questing in Nagrand reached there by foot before this quest even pop up. var lv_screenshots = [{\"id\":434732,\"user\":\"Rantsi\",\"date\":\"2014-11-15T19:45:06-06:00\",\"width\":1920,\"height\":1080,\"type\":5,\"typeId\":37184,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":10258,\"user\":\"985015\",\"date\":\"2014-11-12T01:36:50-06:00\",\"videoType\":1,\"videoId\":\"f-O1wBtfiUk\",\"type\":5,\"typeId\":37184,\"url\":null,\"sticky\":1},{\"id\":10259,\"user\":\"985015\",\"date\":\"2014-11-12T01:36:50-06:00\",\"videoType\":1,\"videoId\":\"nzga_C5hOBY\",\"type\":5,\"typeId\":37184,\"url\":null},{\"id\":46262,\"user\":\"1440987\",\"date\":\"2015-03-12T15:45:26-05:00\",\"videoType\":1,\"videoId\":\"mhXxtaKPtdk\",\"type\":5,\"typeId\":37184,\"url\":null}]; var g_pageInfo = {\"type\":5,\"typeId\":37184,\"name\":\"Taking the Fight to Nagrand\"}; WH.Layout.set({breadcrumb: [0, 3, 13, 6755]}); //]]> // Links Taking the Fight to Nagrand Speak with Lieutenant Balfor at the caravan in Nagrand . &nbsp; Flight taken &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37201, 0, 0, 'Did you want to pet battle or just talk...', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37206, 0, 0, 'Tarr destroy your face!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37207, 0, 0, 'Can you defeat me?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37434, 0, 0, 'Have you completed your challenge?', 0);
