INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37523, 0, 0, 'This quest can be done ridiculously fast. At the Gorian Proving Grounds there is a building @ 58,15 with one elite in it who dies surprisingly fast. Inside the building are 4 slave posts that respawn within 10 seconds and give 4% completion each. Kill the elite, stay inside the building for 1 minute and you are done ! Easiest 800 Apexis Crystals ever.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37524, 0, 0, 'The ogres at the Gorian Proving Grounds be rousin\' champions to turn against our forces in Nagrand. A decisive assault on their training grounds should prevent dem from musterin\' the forces dey be needin\' to stand against us, and will help remind them that we are not an enemy they want to be makin\'.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37627, 0, 0, '[PH]Commander! You just missed a group of rangari with some disturbing news. The Shadowmoon Orcs have been spotted in the hills above Anguish Fortress. The scouts reported seeing strange rituals and beings of pure darkness. Those orcs must be up there trying to summon more minions from the Void! If we do not intervene all we have gained in Shadowmoon Valley might be lost!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37779, 0, 0, 'You will receive: Order Resources WH.ge(\'icontab-icon1\').appendChild(g_gatheredcurrencies.createIcon(1220, 1, \"200\"));', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37891, 0, 0, 'If you have flying and stables, you complete the daily without dismounting or killing mobs. The objectives that give credit are (Wowhead is missing coords and I had to manually go find them, so there might be more that aren\'t listed here): Iron Horde Banner (+3) /way 36.6 32.2 /way 36.0 33.4 /way 36.4 35.6 /way 38.0 36.2 /way 37.4 34.6 /way 38.4 34.4 /way 38.6 34.4 /way 39.6 34.6 /way 40.6 34.6 /way 40.2 32.0 /way 42.0 35.6 /way 42.4 37.6 /way 40.8 38.2 /way 39.2 39.0 /way 38.8 41.0 /way 37.4 43.2 /way 36.4 43.2 /way 36.4 42.8 /way 36.6 40.4 Box of Iron Horde Equipment (+6) /way 40.2 32.4 /way 39.6 33.4 /way 38.4 36.2 /way 39.6 38.3 /way 43.0 34.9 /way 40.3 33.6 /way 41.5 36.7 /way 36.9 33.7 /way 37.6 33.4 /way 36.6 41.9 /way 37.8 41.8 /way 39.5 40.8 True Iron Bomb (+1) /way 39.0 36.5 /way 39.0 36.6 /way 37.6 34.2 /way 36.8 33.4 /way 37.2 38.3 /way 36.4 39.7 /way 39.5 39.4 /way 40.0 37.0 /way 41.7 38.5 /way 41.8 32.7 Iron Battle Engine (+5) - requires bomb and need to dismount when throwing it /way 37.2 32.4 /way 39.6 32.6 /way 36.8 35.0 /way 38.2 34.8 /way 39.0 35.0 /way 39.8 36.0 /way 37.4 36.6 /way 38.0 38.6 /way 39.4 38.2 /way 36.9 37.1', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (37940, 0, 0, 'If you have flying and stables, you complete the daily without dismounting or killing mobs. The objectives that give credit are (Wowhead is missing coords and I had to manually go find them, so there might be more that aren\'t listed here): Iron Horde Banner (+3) /way 36.6 32.2 /way 36.0 33.4 /way 36.4 35.6 /way 38.0 36.2 /way 37.4 34.6 /way 38.4 34.4 /way 38.6 34.4 /way 39.6 34.6 /way 40.6 34.6 /way 40.2 32.0 /way 42.0 35.6 /way 42.4 37.6 /way 40.8 38.2 /way 39.2 39.0 /way 38.8 41.0 /way 37.4 43.2 /way 36.4 43.2 /way 36.4 42.8 /way 36.6 40.4 Box of Iron Horde Equipment (+6) /way 40.2 32.4 /way 39.6 33.4 /way 38.4 36.2 /way 39.6 38.3 /way 43.0 34.9 /way 40.3 33.6 /way 41.5 36.7 /way 36.9 33.7 /way 37.6 33.4 /way 36.6 41.9 /way 37.8 41.8 /way 39.5 40.8 True Iron Bomb (+1) /way 39.0 36.5 /way 39.0 36.6 /way 37.6 34.2 /way 36.8 33.4 /way 37.2 38.3 /way 36.4 39.7 /way 39.5 39.4 /way 40.0 37.0 /way 41.7 38.5 /way 41.8 32.7 Iron Battle Engine (+5) - requires bomb and need to dismount when throwing it /way 37.2 32.4 /way 39.6 32.6 /way 36.8 35.0 /way 38.2 34.8 /way 39.0 35.0 /way 39.8 36.0 /way 37.4 36.6 /way 38.0 38.6 /way 39.4 38.2 /way 36.9 37.1 var lv_screenshots = [{\"id\":478252,\"user\":\"unholydriver\",\"date\":\"2015-08-11T18:09:13-05:00\",\"width\":1920,\"height\":1080,\"type\":5,\"typeId\":37940,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":70333,\"user\":\"1440987\",\"date\":\"2015-06-05T20:30:48-05:00\",\"videoType\":1,\"videoId\":\"I3QG6zAba80\",\"type\":5,\"typeId\":37940,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":37940,\"name\":\"Assault on Ironhold Harbor\"}; WH.Layout.set({breadcrumb: [0, 3, 13, 6723]}); //]]> // Links Assault on Ironhold Harbor Assault the Iron Horde reinforcements at Ironhold Harbor in Tanaan Jungle . &nbsp; Assault the Iron Horde forces at Ironhold Harbor &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (38179, 0, 0, 'Botani and the plant monstrosities they conjure have been slowly encroaching on our outposts in the north. For every plant we kill, new ones seem to rise in its place. Rokhan has put together a plan for striking at the heart of their lands, in Everbloom Wilds. He thinks this will draw them back into the jungles of Gorgrond, giving us more room to maneuver around them.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (38193, 0, 0, 'Massive ogron have been battering our frontlines, and no matter how many we down, there seem to be more to replace them. Most of these ogron appear to be coming from the Broken Precipice , deep in western Nagrand. If we\'re to stand a chance in the coming battles, we need to find a way to remove these ogron from the battlefield.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (38196, 0, 0, 'This quest can be started by purchasing the Scouting Missive: Darktide Roost from Sergeant Crowler in player garrisons. var lv_screenshots = [{\"id\":1059969,\"user\":\"auryunderground\",\"date\":\"2022-04-26T02:45:28-05:00\",\"width\":1600,\"height\":900,\"type\":5,\"typeId\":38196,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":38196,\"name\":\"Missive: Assault on Darktide Roost\"}; WH.Layout.set({breadcrumb: [0, 3, 26, -403]}); //]]> // Links Missive: Assault on Darktide Roost Assault the Iron Horde forces at Darktide Roost in Shadowmoon Valley. &nbsp; Assault the Iron Horde forces at Darktide Roost &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (38250, 0, 0, 'Yesterday\'s patch notes said they fixed the bug on the \'time to strike\' achieve. Nope, nadda, uh huh. Still no credit for this and other areas. Wish blizz would stop lying. var lv_screenshots = [{\"id\":472768,\"user\":\"Rantsi\",\"date\":\"2015-06-26T21:53:39-05:00\",\"width\":1920,\"height\":1080,\"type\":5,\"typeId\":38250,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":70319,\"user\":\"1440987\",\"date\":\"2015-06-05T20:30:48-05:00\",\"videoType\":1,\"videoId\":\"LmAS83BHOps\",\"type\":5,\"typeId\":38250,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":38250,\"name\":\"Assault on the Ruins of Kra\'nak\"}; WH.Layout.set({breadcrumb: [0, 3, 13, 6723]}); //]]> // Links Assault on the Ruins of Kra\'nak Assault the Shadow Council forces at the Ruins of Kra\'nak in Tanaan Jungle . &nbsp; Assault the Shadow Council forces at the Ruins of Kra\'nak &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (38441, 0, 0, 'The Iron Horde is growing stronger each day as their war machines are empowered with fel magic. We have even obtained word that they are constructing a Fel Reaver! Head to the Fel Forge and destroy their forces before we are overwhelmed.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (38585, 0, 0, 'If you have flying and stables you can just go around freeing Lion\'s Watch Captive without ever dismounting.They are the &quot;only&quot; objective in Throne of Kil\'jaeden that doesn\'t involve killing mobs. Gives you 4% credit for every one you release. Does not share spawn location with Horde counterpart Vol\'mar Captive . Coords for those who are soloing: /way 53.0 20.0 /way 52.4 23.0 /way 52.8 24.0 /way 54.8 23.8 /way 50.4 23.6 /way 53.2 26.8 /way 54.4 27.2 /tar Lion\'s Watch Captive is useful too. var lv_screenshots = [{\"id\":474751,\"user\":\"Eido\",\"date\":\"2015-07-11T22:10:55-05:00\",\"width\":1646,\"height\":754,\"type\":5,\"typeId\":38585,\"imageType\":2,\"staffOnly\":false,\"sticky\":1},{\"id\":474754,\"user\":\"Eido\",\"date\":\"2015-07-11T22:13:10-05:00\",\"width\":1549,\"height\":757,\"type\":5,\"typeId\":38585,\"imageType\":2,\"staffOnly\":false},{\"id\":474757,\"user\":\"Eido\",\"date\":\"2015-07-11T22:16:06-05:00\",\"width\":1174,\"height\":785,\"type\":5,\"typeId\":38585,\"imageType\":2,\"staffOnly\":false},{\"id\":537559,\"user\":\"PandariaRPLore\",\"date\":\"2016-07-01T10:59:02-05:00\",\"width\":1920,\"height\":1080,\"type\":5,\"typeId\":38585,\"imageType\":2,\"staffOnly\":false}]; var lv_videos = [{\"id\":70102,\"user\":\"1440987\",\"date\":\"2015-06-05T20:30:47-05:00\",\"videoType\":1,\"videoId\":\"Jfy3a0ioRd8\",\"type\":5,\"typeId\":38585,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":38585,\"name\":\"Assault on the Throne of Kil\'jaeden\"}; WH.Layout.set({breadcrumb: [0, 3, 13, 6723]}); //]]> // Links Assault on the Throne of Kil\'jaeden Defeat the Shadow Council at the Throne of Kil\'jaeden in Tanaan Jungle . &nbsp; Assault the Shadow Council forces at the Throne of Kil\'jaeden &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (38586, 0, 0, 'Assault on the Throne of Kil\'jaeden &gt;&gt;&gt;&gt;&gt; https://youtu.be/eFsjrfKngWU', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (38711, 0, 0, 'I was standing for a while - reading the comments on this, when I got attacked - fought and I had the q popping up :)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (39317, 0, 0, 'Can anyone explain to me how you actually get this quest? The guy doesn\'t want to give it, and I\'m pretty sure I\'ve done every other quest in the area. I\'ve now completed every quest in the area, and this quest was never on offer. I have submitted a ticket to support to find out what\'s wrong with this quest, and if it\'s bugged since the patch. Weirdly, it seems the Skyhorn questline can be completed without this quest, and without several other quest chains which you can come back and do later on. This makes the Skyhorn area the quickest of the zones you need to complete to get the Tauren all happy-happy friends again. EDIT According to Blizzard Support, this quest has been removed: &quot;Siege of Crawliac, according to WoWHead, has no source, and the description shows Placeholder text. Considering final versions of quests tend not to have tags to signify placeholder, it\'s a safe assumption that this quest is not available.&quot; EDIT II I researched into this, and &quot;Siege of Crawliac&quot; is/was a bonus quest. There\'s exisiting footage for this pre-launch, but I couldn\'t find any to support a live version. Therefore, it may still have been removed as the blue stated, but it\'s possible it\'s another quest that simply doesn\'t show up for level 110 (like Shipwreck Cove)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (39343, 0, 0, 'You find tubing formed from a bendable sort of glass. It appears as though Grimoira was using it to suck out the insides of her victims. Its magical properties, however, would seem ideal for use on an advanced alchemy table.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (39424, 0, 0, 'I don\'t know if anyone else has this problem, but I\'ve noticed a problem on the world quest for this area. The weapon racks are highlighted but can\'t be interacted with. This has made it a whole lot longer to complete than it normally would.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (39720, 0, 0, '2025 - if you fly here and see nothing quest-related at the Isle of Shadows in Shadowmoon, logout and back in again. I had this problem. Flying out, phasing, etc did not work for me, but logging out then right back in did work. var lv_screenshots = [{\"id\":668695,\"user\":\"Rantsi\",\"date\":\"2017-10-25T13:02:42-05:00\",\"width\":1509,\"height\":1487,\"type\":5,\"typeId\":39720,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":345245,\"user\":\"gtulgar1903\",\"date\":\"2024-11-03T22:23:13-06:00\",\"videoType\":1,\"videoId\":\"gx5ESXIB0OU\",\"type\":5,\"typeId\":39720,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":39720,\"name\":\"Foul Fertilizer\"}; WH.Layout.set({breadcrumb: [0, 3, 9, -1003]}); //]]> // Links Foul Fertilizer Destroy 8 kegs of Dread Fertilizer . &nbsp; Fertilizer destroyed &nbsp;( 8 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (39757, 0, 0, 'Greetings, Deathlord. The blades you hold, while magnificent, have much untapped potential. As you harvest the souls of your enemies their power will continue to grow. Grand Master Corvus has studied new techniques that may be of use to you, &lt;my lord/my lady&gt;. You can find him working the forges on the upper level.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (39761, 0, 0, 'I\'ve been working for many years to improve the forges. This weapon will be the perfect demonstration of the Soul Forge, their latest design! We can take your artifact to the forge and shape it to make use of the power it contains, provided you\'ve fed your weapon enough souls first. Let\'s give it a little try, eh?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (39937, 0, 0, 'Even though they are opposites, one can not exist without the other.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40111, 0, 0, 'You will receive: Order Resources WH.ge(\'icontab-icon1\').appendChild(g_gatheredcurrencies.createIcon(1220, 1, \"200\"));', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40143, 0, 0, 'This is the first part of a chain to obtain Mother\'s Skinning Knife: How to get the toy: Notes: I started with level 1 Skinning and was level 105 on my DH. I just wanted the Toy... 1. Kill and skin Adult Squalhunters, obtain Unfinished Treatise on the Properties of Stormscale (took around 30 kills or so, may possibly drop from Juvenile mobs as well) 2. Bring Treatise to Kondal Huntsworn in Dalaran 3. Pick up the following quest(s) from Kondal: Seymour and Agnes (he has a second quest for Azsuna, you don\'t need this for the toy) 4. Locate Seymour at 45.6, 35.8 in Stormheim and turn in quest 5. Pick up quests: Mother\'s Prized Knife, and Red Eyed Revenge from Seymour 6. Travel up the mountain and pick up Mother\'s Prized Knife at 46.12, 33.62 7. Kill 15 Adult Squalhunters to complete Red Eyed Revenge (you need to complete both quests) 8. Turn in both quests at Seymour, pick up: Drakol\'nir Must Die. 9. Travel to cave at 47.48, 28.34 (just up the hill a little, around the corner), kill Drakol\'nir, pick up Scale of Drakol\'nir 10. Turn in completed quest to Seymour, collect Toy as your reward', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40277, 0, 0, 'I found a much easier way to do the Magic requirement. I did not have a leveled broom or voidcaller. I used: Netherspace Abyssal (2,1,1) Lofty Libram (1,2,2) Jade Oozeling (2,1,1) Opened with Meteor Strike Immolation Immolate Jinx until dead Rocket enters battle, Meteor Strike strike - it will hit before he puts up nature ward Reapply Immolation Immolate until the Abyssal dies, swap in the Libram Amp Magic Arcane Blast x2, Rocket dies and Marshmallow enters Curse of Doom, Libram will die, bring in the Oozeling Expunge Absorb to be safe, curse of doom killed marshmallow, took 20 rounds to win', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40280, 0, 0, 'Ragnaros Watch and Learn Killed it with Lil Ragnaros (1,2,1) Molten Corgi (2,1,2), Elementium Geode (1,X,X) (As 3rd pet you basically just need something to finish his last flying pet off)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40337, 0, 0, 'I killed it with 1- Iron Starlette 2- Unborn Val\'kyr 3- Temple Snake what u have to do as Iron Starlette is to use wind-up once then use explode u have to use 2 abilities because after that u will switch to Unborn and use Curse of Doom and Haunt before he applies the debuff on u, then u switch to Temple snake and use Burrow to avoid the debuff, after that use Hiss and then use Poison Fang. the snake should be dead and Unborn should be up again. start spamming shadow shock till he dies. The first time it didn\'t work, but it worked the second time. I guess i wasn\'t lucky the first time.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40896, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40925, 0, 0, 'This World Quest doesn\'t seem to appear that often. I have now waited for almost a month and I have got Stonebinder Bounty TWICE now, which appears in the same cave. Maybe it\'s to prevent people from buying limitless amounts of Blue Drog from Heavy Brewbrul who becomes friendly during this World Quest lol ---- Note that for you to see this World Quest, you have to have completed Dargrul and the Hammer for it to appear. var lv_screenshots = [{\"id\":600142,\"user\":\"deviantsynapses\",\"date\":\"2017-01-12T14:39:04-06:00\",\"width\":1051,\"height\":880,\"type\":5,\"typeId\":40925,\"imageType\":2,\"staffOnly\":false},{\"id\":600143,\"user\":\"deviantsynapses\",\"date\":\"2017-01-12T14:39:21-06:00\",\"width\":1271,\"height\":600,\"type\":5,\"typeId\":40925,\"imageType\":2,\"staffOnly\":false},{\"id\":600144,\"user\":\"deviantsynapses\",\"date\":\"2017-01-12T14:39:37-06:00\",\"width\":854,\"height\":746,\"type\":5,\"typeId\":40925,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":108845,\"user\":\"Termic\",\"date\":\"2016-10-13T11:39:05-05:00\",\"videoType\":1,\"videoId\":\"H3GEFNXBvOg\",\"type\":5,\"typeId\":40925,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":40925,\"name\":\"Bitestone Burglary\"}; WH.Layout.set({breadcrumb: [0, 3, 14, 7503]}); //]]> // Links Bitestone Burglary &nbsp; Obtain a Disguise Drog &nbsp;( 1 ) &nbsp; Bitestone burgled &nbsp;( 1 ) &nbsp; Contaminate Stolen Drog &nbsp;( 50 ) Stonedark Crystal &nbsp;( 20 ) &nbsp; Prized Racing Snail recovered &nbsp;( 7 ) Private Stalk &nbsp;( 10 ) Stinky Fish Head &nbsp;( 20 ) Jar of Floog &nbsp;( 10 ) Prized Racing Snail &nbsp;( 1 ) WH.ge(\'icon-list-icon1\').appendChild(g_items.createIcon(127271, 0, 20, null, null)); WH.ge(\'icon-list-icon2\').appendChild(g_items.createIcon(133874, 0, 10, null, null)); WH.ge(\'icon-list-icon3\').appendChild(g_items.createIcon(134015, 0, 20, null, null)); WH.ge(\'icon-list-icon4\').appendChild(g_items.createIcon(134016, 0, 10, null, null)); WH.ge(\'icon-list-icon5\').appendChild(g_items.createIcon(133808, 0, 1, null, null)); {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40935, 0, 0, 'If this is your 2nd or 3rd Artifact and the deathgate takes you to your class hall you need to find Darion by the SoulForge to complete the quest. You won\'t go back to the Frozen Throne. Also the map marker is incorrect.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40960, 0, 0, 'Dunno if anything changed but i was doing the rare fish on my alt with a few of the uniques i caught on my main. I got the 3 fish from aszhara, and 2 fish from valshara, then i got the pearl while trying for the 3rd rare. Sooooo i guess you dont need the achievement on alts anymore?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (40985, 0, 0, 'Upon completion of this quest you will gain: 150 reputation with Highmountain Tribe See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(40985)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(40985))\");', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41013, 0, 0, 'this is THE dumbest thing blizz has ever put into the game. &quot;kill 10 elites to complete...but wait. youre gonna have people there killing you making ti so you cant kill the elites.&quot;', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41014, 0, 0, 'As of patch 7.2.5 Fury Road works okay. Obtain a crystal from Shardmaster Ufrogg . Locate the flight master at Thunder Totem. Take the nearby trestle bridge. In the distance you can see the cave you\'ll enter to farm Unrefined Gem s. Shardmaster Ufrogg is standing (49.2, 55.2) next to a tauren defender. Click to interact and he gives you a crystal. If you\'re disconnected, walk up to him again and get another crystal. The crystal is a Rageshard that appears on screen next to the quest count. Use: Summon a Rageshard mount. As soon as you click on the Rageshard you\'ll see the vehicle controls. But your avatar is actually riding the Rageshard (see screenshot). Obtain 100 Unrefined Gem s Ride into the cave. Don\'t bother to kill the Enraged Ambershard s outside the cave. They don\'t drop Unrefined Gem s and this isn\'t a mining quest. Inside the cave use ability #3 to jump to your target - an Enraged Ambershard . Attack with ability #1 - a claw, and ability #2 - a shard. Unrefined Gem pinball When you kill an Enraged Ambershard you\'ll get only about 5 Unrefined Gem s. So look for the purple crystals on the ground and run through them as fast as possible (before they despawn and before someone ninja\'s them). Each one chimes on contact and counts toward the 100 Unrefined Gem s you need. You can kill the first Enraged Ambershard s you meet in the cave. As you you move farther into the cave you can mouseover an Enraged Ambershard to check if it counts toward the quest. If you don\'t see the Unrefined Gem count you\'re outside the quest area. If you jump down to the lower level, exit by walking up the reddish wall -- it\'s more of a ramp. There is no way to top up your health. If the health of the Rageshard vehicle/mount goes to zero, you\'re out of the vehicle but still in the cave -- and the mobs walk away. Stay where you are and resummon the mount by clicking on the Rageshard icon. It\'ll have full health and so will you. No grave yard.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41077, 0, 0, 'Dont worry about this WQ in remix, We\'re too op that the quest doesnt register correctly var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":41077,\"name\":\"Munitions Testing\"}; WH.Layout.set({breadcrumb: [0, 3, 14, 7503]}); //]]> // Links Munitions Testing &nbsp; Speak to Gertie &nbsp;( 1 ) &nbsp; Grab a prototype from Razik\'s weapon rack &nbsp;( 1 ) &nbsp; Hunt animals using Razik\'s prototype &nbsp;(15) &nbsp; Icefang Howler &nbsp;( 1 ) &nbsp; Icefang Packleader &nbsp;( 1 ) &nbsp; Kill Credit: Munitions Testing &nbsp;( 1 ) &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41189, 0, 0, 'The reward of this quest line is Prizerock Neckband for A Keen Eye and This Side Up . This Side Up is itself required for Fighting with Style: Upgraded for unlocking additional artifact weapon appearances.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41273, 0, 0, 'On this world quest you are required to put balloons on the Enormous Sea Crab at the bottom of the sea. You need to talk to the npc to get the balloons. The coords of her location can be found here: NOTE: She\'s on the water not below the water. She is sitting on the boat! 28.70, 49.40 or you use macro below: /way 28.70, 49.40 Npc for the balloons Demonstration video below: https://www.youtube.com/watch?v=15O610ZPj6o', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41308, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41509, 0, 0, 'Just completed this quest as well. I came across it the same way as the other poster, by stumbling across it in the same location just south of the Meredil flight path. Completion of the quest didn\'t give me a reward popup, but just above &quot;Felslate Basilisks completed.&quot; was an entry. &quot;You receive item: Felslatex20 So I expect that the quest reward is simply 20 Felslate on top of whatever you\'ve garnered from killing the Basilisks.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41623, 0, 0, 'I done this quest after a long story with bug. If you bug just try restart wow again, it may fix the issue with this quest. Here a video i made for this quest https://www.youtube.com/watch?v=V5clS2Pujvg', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41628, 0, 0, 'Shadowlands Pre-Patch tldr; use the \'boss button\' to summon the dragon flight as soon as you get to Coldarra. Button may disappear. If doing this quest chain at a level below flying (level 30, I was level 16), I learned that I had to use the \'boss button\' to summon the dragon flight, right away; otherwise, the button disappeared after a few minutes. I had to abandon the quest, fly all they way back to Dalaran, then trek back down to the Azure Dragonshrine in Dragonblight (just the edge of the shrine), to get the quest back.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41629, 0, 0, 'You have to slay small arcane elementals, which can be found on the ground across the Nexus. Dont kill ethernals, they give no count. Harnessing the Holy Fire - www.youtube.com/watch?v=qYgORWXNcbk This quest is a part of Priest class hall quest campaign. Full chain is under the spoiler, you can check your progress through it: _ Priest class hall campaign 1 98 Priestly Matters http://www.youtube.com/watch?v=j-8twzW4oUA 2 98 A Legend You Can Hold First artifact chosen . Xal\'atath, Blade of the Black Empire quest chain 98 Blade in Twilight Xal\'atath, Blade of the Black Empire http://www.youtube.com/watch?v=kyQCNiG9NUw . T\'uure, Beacon of the Naaru quest chain 98 The Vindicator\'s Plea http://www.youtube.com/watch?v=D1nYyIRMgPk 98 House Call http://www.youtube.com/watch?v=e2tSO1nP1uI 98 Out of the Darkness http://www.youtube.com/watch?v=Dt8GX6Niaxc 98 Salvation From On High http://www.youtube.com/watch?v=TqO-wrxPYuA 98 Return of the Light T\'uure, Beacon of the Naaru https://www.youtube.com/watch?v=y6rkxivWOJ4 . Light\'s Wrath quest chain 98 The Light\'s Wrath https://www.youtube.com/watch?v=4jRO-6WWAWE 98 A New Threat http://www.youtube.com/watch?v=H4igYKsJ8M4 98 A Forgotten Enemy http://www.youtube.com/watch?v=rzfgUKJROTs 98 Eyes of the Dragon http://www.youtube.com/watch?v=4ZV529p1Tpo 98 Harnessing the Holy Fire http://www.youtube.com/watch?v=qYgORWXNcbk 98 Unleashing Judgment http://www.youtube.com/watch?v=gFiscmmDGko 98 The Nexus Vault http://www.youtube.com/watch?v=H-IIB5pf-rs 98 A Gift of Time Light\'s Wrath https://youtu.be/zY_UeQKzUhc 3 98 The Light and the Void http://www.youtube.com/watch?v=sUvMdR0MgXs 4 98 Artifacts Need Artificers https://youtu.be/jivv5fW4BYQ 5 98 Empowering Your Artifact Invoke the Light , Follower of the Light or Void Siphon 6 98 Actions on Azeroth Choose a zone to attack 7 101 Rise, Champions