INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41896, 0, 0, 'Sadly, turning into a murloc loses you 80% of your health, so you die instantly to other players and don\'t get much of a chance to use your fun new abilities.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41930, 0, 0, 'Excellent. Saved me a lot of bother trying to find best way ther. Thanks', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41931, 0, 0, 'Finally this quest is up! Never seen it before.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (41957, 0, 0, 'If you don´t manage to find the quest at the said NPC in my case Archmage Kalec in The Violet Citadel offered me the quest &quot;A gift of time&quot; to go speak with Alonso Faol.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42005, 0, 0, 'The dialog when speaking to Tahu Sagewind : I greet you, &lt;name&gt;. I am glad to help. Orik says you can speak to these spirits, how do we begin? I misjudged how long ago this happened. I will need more time to prepare myself for the ritual. In the meantime, I have attuned this stone to the scroll Orik brought. Certain graves will glow to your mind\'s eye. Go to them and concentrate on the stone to see if you have found the correct grave. We want the writer himself, not a descendent (sic) or ancestor. Okay.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42009, 0, 0, 'this mision its imposible to do and they dont fix it -.-', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42011, 0, 0, 'Staff Stage (Pre-Patch Shadowlands) Level 12 and Arcane, I had to switch specs in order to see the scroll extra action button. I stood under the dome and couldn\'t figure out what to do next. I switched to fire and the &quot;use scroll&quot; button appeared. I switched back to arcane and finished the quest.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42015, 0, 0, 'Used Onyxian Whelpling : 2, 1, 2 Scourged Whelpling : 2, 2, 1 Any other pet.. Onyxian Whelpling &gt;&gt; Tail sweep with Healing Flame as needed. Take care not to kill 1st pet when it casts Dark Rebirth I killed first 2 pets with Onyxian Whelpling and then used Tail Sweep with Scourged Whelpling until 3rd pet died.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42023, 0, 0, 'If you\'re a melee, you\'ll have a lot of fun with the gibfest. If you\'re a caster, this quest will remind you about everything you hate in this expansion.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42025, 0, 0, 'Is it just me or is the name of this world quest not all that PG-13?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42026, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42065, 0, 0, 'In my book, the best way to do this, is make sure you free the miners as you go down. If there are a few people doing this, you may have to backtrack to pick them up a couple times. Try to BE at the bottom when you complete the first 2 quests. Once you\'re in, there\'s no reason to go back out unless you go out via the portal after you kill the Mistress. It\'s not hard to follow the mini-map arrow to the Mistress.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42082, 0, 0, 'i dont have a lodestone? i\'m so confused. how do i get it?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42111, 0, 0, 'Best mobs for killing are Felsoul Inquisitor s, i guess. Their deaths sightly fill your quest progress bar and the they also have a chance to drop a battle pet — Eye of Inquisition . Aggressive Reconnaisance — https://www.youtube.com/watch?v=E_Ip8uKGFCY', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42112, 0, 0, 'You will quickly find out just how annoying this is as everyone is scrambling to grab the blue whelpling spawns. Instead, I found a nice alternative. Simply collect 8 crystals, and then head to the water. Start at 47.41, 16.62 and then swim west a couple feet to 47.04, 16.85. There are always whelpling spawns in these two exact locations and the respawn timer is exactly 34 seconds after casting the crystal ability. Here is a picture for reference on the location.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42170, 0, 0, 'Dreamweaver Provisions has a very rare chance to contain Thistleleaf Adventurer . var lv_screenshots = []; var lv_videos = [{\"id\":392355,\"user\":\"gtulgar1903\",\"date\":\"2025-11-19T14:47:52-06:00\",\"videoType\":1,\"videoId\":\"iprA2k2YPh8\",\"type\":5,\"typeId\":42170,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":42170,\"name\":\"The Dreamweavers\"}; WH.Layout.set({breadcrumb: [0, 3, 14, 7558]}); //]]> // Links The Dreamweavers Complete any 4 world quests in Val\'sharah . &nbsp; Complete 4 world quests in Val\'sharah &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42190, 0, 0, 'Spring Striders : /way 49.2, 69.8 (at least 4 here) Vale Flitter : /way 60.8, 77.9 (at least 3 here) Shimmering Aquafly : /way 53.2, 83.7 (at least 2; more in the surrounding area) Just waypoints: /way Val\'Sharah 49.2, 69.8 Spring Striders /way Val\'Sharah 60.8, 77.9 Vale Flitter /way Val\'Sharah 53.2, 83.7 Shimmering Aquafly If you can\'t find any, check in the immediate area surrounding. A lot of people are doing pet battles due to World Quests now.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42233, 0, 0, 'Assist the Tauren of Highmountain by completing 4 world quests.', 0);
