INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42725, 0, 0, 'TL;DR: Kill Nightborne Vintners , they always drop a cask. Thanks for clearing that up inktomi! Upon further research (sorry, masses of dead guards :( ), I have concluded that the guards drop no casks. So unless someone has positive poof of a cask dropping from a guard, we\'ll go with inktomi\'s suggestion :)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42781, 0, 0, 'The Duskwatch Weaponry can be found in The Gilded Market in the edges of the area where you fight Patrol Captain Gerdo and several more are to the south over the first bridge. There are packs of mobs around the edges of each area near the weaponry, so let your group know if you\'re going for these items before you clear the dungeon.', 0);
