INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42805, 0, 0, 'During the invasion you can get 2 chests - Small Legion Chest and Large Legion Chest These chests contains 700ivl armor and chance to get scaling weapon like Fel Lord\'s Warmace which can be improved to 725ilvl, also you have small chance to get Coalesced Fel from Large Legion Chest . Very usefull addon for invasions https://mods.curse.com/addons/wow/legioninvasiontimer https://www.youtube.com/watch?v=maQV0R2ULow var lv_screenshots = []; var lv_videos = [{\"id\":98727,\"user\":\"bonecoll\",\"date\":\"2016-08-12T11:45:34-05:00\",\"videoType\":1,\"videoId\":\"maQV0R2ULow\",\"type\":5,\"typeId\":42805,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":42805,\"name\":\"Invasion: Hillsbrad Foothills\"}; WH.Layout.set({breadcrumb: [0, 3, 0, 267]}); //]]> // Links Invasion: Hillsbrad Foothills See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(42805)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(42805))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42830, 0, 0, 'If you\'re not super observant like me, you\'d wonder where the Shadescale Flyeaters are... they\'re the mana wyrm-looking dudes scattered in the water surrounding the vineyard! :)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42880, 0, 0, 'As alot of people both here and in the forums have stated, jumping in the vat WILL BREAK THE WQ but if you never have to jump in it, it can be completed. Completetly ludacris that it hasn\'t been fixed yet.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (42924, 0, 0, 'This quest was designed by a sadist. Go into a random group dungeon to find 5 items that are crazy hidden, including one on the BOTTOM of a boss platform at an angle no one would realistically use, and expect the group to be patient while people find their blades. Complete waste of time. BTW as of 8/25 it is now 1 per person as you click them. No longer shared pickup or 5-for-1. 0/10 Blizzard. Not a good attempt here.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43007, 0, 0, 'If you are attempting All The Things completion, you will get this quest by simply leaving the Hall of Shadows. As soon as I ported out, Valeera found me to offer the quest. As long as you don\'t pick up/complete Rise, Champions or the other quest(s) the NPC has, you\'ll have this offered to you. var lv_screenshots = [{\"id\":564399,\"user\":\"Rantsi\",\"date\":\"2016-09-07T19:49:19-05:00\",\"width\":1538,\"height\":1017,\"type\":5,\"typeId\":43007,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":101272,\"user\":\"1473853\",\"date\":\"2016-09-03T08:10:42-05:00\",\"videoType\":1,\"videoId\":\"QTAKYbuNt44\",\"type\":5,\"typeId\":43007,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":43007,\"name\":\"Return to the Chamber of Shadows\"}; WH.Layout.set({breadcrumb: [0, 3, 27, -424]}); //]]> // Links Return to the Chamber of Shadows Speak with Lord Jorach Ravenholdt in the Chamber of Shadows. {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43176, 0, 0, 'This is the last one i need for the Adventurer of Val\'sharah achievement but it will not trigger for me, despite me trying all the tricks posted online, i submitted a ticket and this was the GM response i got: Hey there Hawkyyy, I hope you\'re well mate! Having checked through your ticket and I found that the issue you\'re having with the grell waves is something that is being reported forward right now. You can be sure that our developer team has been made aware of this issue and it will be corrected as soon as possible! We\'re really sorry for any inconvenience caused, thank you very much for taking the time to let us know about it So if you\'re getting this too, we just have to wait until its fixed which will hopefully be soon. Edit: Went back there today (03/06/2018) and as soon as i flew down the encounter triggered, i completed it and got my achievement.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43179, 0, 0, 'This quest is obtained where? Can\'t seem to locate it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43244, 0, 0, 'During the invasion you can get 2 chests - Small Legion Chest and Large Legion Chest These chests contains 700ivl armor and chance to get scaling weapon like Fel Lord\'s Warmace which can be improved to 725ilvl, also you have small chance to get Coalesced Fel from Large Legion Chest . Very usefull addon for invasions https://mods.curse.com/addons/wow/legioninvasiontimer https://www.youtube.com/watch?v=RCkNLmD8BhI', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43245, 0, 0, 'During the invasion you can get 2 chests - Small Legion Chest and Large Legion Chest These chests contains 700ivl armor and chance to get scaling weapon like Fel Lord\'s Warmace which can be improved to 725ilvl, also you have small chance to get Coalesced Fel from Large Legion Chest . Very usefull addon for invasions https://mods.curse.com/addons/wow/legioninvasiontimer https://www.youtube.com/watch?v=4-jN4Pk13lw', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43282, 0, 0, 'The Captive Wyrmtongue is located at 51, 57 just slightly east of Crossroads', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43284, 0, 0, 'The Captive Wyrmtongue is located at 59, 35 at the gates of Ironforge', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43285, 0, 0, 'The Captive Wyrmtongue is located at 53, 43 NW of Tarren Mill', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43301, 0, 0, 'TOTAL: 260 Nethershard per invasion Nope, not true at all.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43323, 0, 0, 'Let us speak, then, of events that have already come to pass.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43325, 0, 0, 'Just a heads up: When you are on the manasaber, make sure you don\'t target something and hit the 1 key (Attack) just to see what happens. I got dismounted with a bar at 95%, had to fight Warbringer Mox\'na and his two felhounds before I could go back to the starting point. I was unable to mount the manasaber again, as I still had the 24 hour debuff that we get while on the manasaber. I got on the flight path, landed, still had the debuff. Then I used my DK\'s Deathgate, got the loading screen for Acherus followed immediately by the Azsuna loading screen, and I was back at the starting point, thank goodness, and was able to re-mount and restart the quest.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43327, 0, 0, 'Of course any failure drops you to your death. Blizzard apparently thinks running to your corpse multiple times is where the fun is at.', 0);
