INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43377, 0, 0, 'I was getting really confused because the action button was not appearing, but it had actually moved from the place it usually is on the screen. Rather than being in the centre of the UI, it was right over my character portrait. If you can\'t see the button, have a look around your screen and it might be hiding somewhere else!', 0);
