INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43505, 0, 0, 'I can\'t turn in this quest and it\'s been forever omg... i tried everything in this thread but he still won\'t appear at the quest mark next to senagos even thought sengaos literally greets him... kalecgos is just invisible :/ anyone facing the same issue?', 0);
