INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43769, 0, 0, 'There is no real &quot;trick&quot; to this one (Stormhelm) simply mount the cat, and run along the road from the quest giver to Forsaken Foothold. past the flight point, turn left up the hill toward Blackbeak Overlook and about halfway up the hill you complete the quest and get teleported back to the start. Make sure you run through the blue light spots. Takes maybe 3 min.', 0);
