INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43959, 0, 0, 'Quick notes.. First part there are several stairs around you can hang out in the middle of as the Stelleris Libertine\'s march their paths.. Second part is if you have an issue with Covelyn you can wait for others before attacking. Alliance or Horde, it doesn\'t matter you still get credit regardless of who starts the fight.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (43964, 0, 0, 'Whatever you do, don\'t get drunk. The effect doesn\'t dissapear when you finish the WQ.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (44049, 0, 0, 'This is easily soloed. Just kill groups of the spiderlings and skitterers. They do very little damage and can be killed in mass with an AOE attack. I never encountered a venomspitter.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (44054, 0, 0, 'There are many elite mobs, better hunt for them on a plain, Malignant Stalker - best choice if you do that solo, else go to spider cave or search for Felsworn Betrayer . Demonicide — https://www.youtube.com/watch?v=l19Slo2nb2A', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (44338, 0, 0, 'Classic Khadgar, dropping a major theological bomb as an aside in basically a breadcrumb quest, while zooming around as a head in a ball. Never change, Khadgar.', 0);
