INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (44799, 0, 0, 'Do not use Hex or Polymorph unless it\'s the last run. Ime when the morphed mobs get their base forms back they will aggro you no matter how in the Hell far away you are (if you in the city) AND they will bring many many friends with them including at least one elite. Not worth the hassle imo. YMMV.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (44867, 0, 0, 'Silgryn says: The Duskwatch have taken outposts in the Crimson Thicket. Unleash the Withered at your command and drive them out! ... what withered? Complete: Silgryn says: The Duskwatch presume to push beyond their borders in the midst of a revolution. You repaid them for their arrogance! var lv_screenshots = [{\"id\":665073,\"user\":\"Rantsi\",\"date\":\"2017-10-15T10:22:21-05:00\",\"width\":3207,\"height\":1791,\"type\":5,\"typeId\":44867,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":113526,\"user\":\"JNasty\",\"date\":\"2016-12-09T18:19:14-06:00\",\"videoType\":1,\"videoId\":\"A8gOvnkQp8I\",\"type\":5,\"typeId\":44867,\"url\":null,\"caption\":\"World of Warcraft Contain Their Advance Suramar Legion World Quest Guide\",\"sticky\":1},{\"id\":124400,\"user\":\"Mypciscraze\",\"date\":\"2017-05-09T19:18:19-05:00\",\"videoType\":1,\"videoId\":\"t8td5qVkBmI\",\"type\":5,\"typeId\":44867,\"url\":null,\"caption\":\"Contain their Advance World Quest Suramar World Of Warcraft\"}]; var g_pageInfo = {\"type\":5,\"typeId\":44867,\"name\":\"Contain their Advance\"}; WH.Layout.set({breadcrumb: [0, 3, 14, 7637]}); //]]> // Links Contain their Advance &nbsp; Assault on Felborne Outpost &nbsp;( 1 ) &nbsp; Kill Credit: Normal Felborne slain &nbsp;(13) &nbsp; Felborne Energist &nbsp;( 1 ) &nbsp; Felborne Collaborator &nbsp;( 1 ) &nbsp; Scathing Felbeast &nbsp;( 1 ) &nbsp; Felborne Magus &nbsp;( 1 ) &nbsp; Felborne Marauder &nbsp;( 1 ) &nbsp; Kill Credit: Normal Felborne &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Kill Credit: Elite Felborne slain &nbsp;(9) &nbsp; Felblade Protector &nbsp;( 1 ) &nbsp; Valthis Ama\'ran &nbsp;( 1 ) &nbsp; Kill Credit: Elite Felborne &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Marching Orders &nbsp;( 17 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (44884, 0, 0, 'There are never enough machines around. Forget about doing this during peak hours.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (44894, 0, 0, 'As of Patch 7.1 there are 4 new Falcosaur pets. Each of the pets is associated with a different world quest around the Broken Isles. These pets all provide a quest chain to obtain a different mount. These quest chains require a couple of weeks to complete as each subsequent quest becomes available from your summoned pet after the daily reset after completing the previous quest. To get each pet, you must first kill the Matriarch in the world quest area, which will cause the NPC version of the pet to spawn. The next step is to go to the NPC and interact with it and feed it its favourite food. If you don\'t have the food, you won\'t obtain the pet. There are vendors selling the required foods at the closest flightpaths to each world quest for most of these so just remember to pick some up on your way there! Important note on orphans: I\'ve encountered issues with the orphans not spawning after killing the matriarch. This isn\'t affected by the matriarch\'s nest but it does seem to be affected by getting the last hit on the matriarch. If you can\'t see the orphan after killing the matriarch then you may need to wait for the respawn. To check if you have completed the requirements to see the orphan run the scripts below. Snowfeather Hatchling - Snowfeather Swarm! This pet can be picked up from Orphaned Snowfeather in Highmountain (/way Highmountain 32.5, 28.2) after killing the Snowfeather Matriarch (/way Highmountain 35.1, 21.9). The food it wants is Smoked Elderhorn , which can be picked up from Marius Felbane (/way Highmountain 29.8, 40.0). Summoning this pet offers you the quest Raising Your Snowfeather which starts the quest chain to obtain Snowfeather Hunter . Subsequent quests: The Smell of Humans (Alliance) or The Smell of Orcs (Horde) &gt; Hunting Lesson: Northern Hawk Owls &gt; Allies in Highmountain &gt; Snowfeather Team Up &gt; Deadly Prey &gt; Hunting Lesson: Spiketail Beaver &gt; The Unfriendly Faction &gt; Snowfeather Bonding &gt; Hunting Lesson: Mudshell Conch &gt; Teamwork Lesson: Naraxas &gt; Hunting Lesson: Coralback Fiddler &gt; Teamwork Lesson: Ursoc &gt; Snowfeather Team Rumble &gt; Snowfeather Reunion /script print(IsQuestFlaggedCompleted(44879)) Bloodgazer Hatchling - Bloodgazer Swarm! This pet can be picked up from Orphaned Bloodgazer in Azsuna (/way Azsuna 35.5, 7.5) after killing the Bloodgazer Matriarch (/way Azsuna 35.6, 5.7). The food it wants is Azsunian Grapes , which can be picked up from Nalysse Dawnsorrow (/way Azsuna 47.2, 41.4) - this one is a long way from the quest area so try to plan ahead or you\'ll be running a long way to find food and will have to kill the matriarch again. Summoning this pet offers you the quest Raising Your Bloodgazer which starts the quest chain to obtain Predatory Bloodgazer . Subsequent quests: The Smell of Draenei (Alliance) or The Smell of Blood Elves (Horde) &gt; Hunting Lesson: Erudite Manafiend &gt; Allies in Azsuna &gt; Bloodgazer Team Up &gt; Dangerous Prey &gt; Hunting Lesson: Fledgling Kingfeather &gt; The Unfavorable Faction &gt; Bloodgazer Bonding &gt; Hunting Lesson: Juvenile Scuttleback &gt; Teamwork Lesson: Serpentrix &gt; Hunting Lesson: Felspider &gt; Teamwork Lesson: Skorpyron &gt; Bloodgazer Team Rumble &gt; Bloodgazer Reunion /script print(IsQuestFlaggedCompleted(44882)) Direbeak Hatchling - Direbeak Swarm! This pet can be picked up from Orphaned Direbeak in Stormheim (/way Stormheim 79.8, 69.6) - jump down from the rocks above to reach here - after killing Direbeak Matriarch (/way Stormheim 79, 76). The food it wants is Pungent Vrykul Gamalost , which can be picked up from Steward Dayton (/way Stormheim 71.6, 60.6). Summoning this pet offers you the quest Raising Your Direbeak which starts the quest chain to obtain Brilliant Direbeak . Subsequent quests: The Smell of Dwarves (Alliance) or The Smell of Tauren (Horde) &gt; Hunting Lesson: Rose Taipan &gt; Allies in Stormheim &gt; Direbeak Team Up &gt; Dire Prey &gt; Hunting Lesson: Tiny Apparition &gt; The Unkindly Faction &gt; Direbeak Bonding &gt; Hunting Lesson: Golden Eaglet &gt; Teamwork Lesson: Fenryr &gt; Hunting Lesson: Stormstruck Beaver &gt; Teamwork Lesson: Krosus &gt; Direbeak Team Rumble &gt; Direbeak Reunion /script print(IsQuestFlaggedCompleted(44880)) Sharptalon Hatchling - Sharptalon Swarm! This pet can be picked up from Orphaned Sharptalon in Val\'Sharah (/way Val\'Sharah 47.0, 10.5) after killing Sharptalon Matriarch (/way Val\'Sharah 48.0, 9.8). This world quest is somewhat awkward to get to but I recommend coming in from Highmountain (glider from a high point in the north-west or water walking around from the coast). The food it wants is Dried Bilberries , which can be picked up from Fialla Sweetberry in Dalaran (/way Dalaran 52.6, 34.4) - there are a variety of vendors in Highmountain who also sell the item should you choose to get to the world quest from there. Summoning this pet offers you the quest Raising Your Sharptalon which starts the quest chain to obtain Viridian Sharptalon . Subsequent quests: The Smell of Night Elves (Alliance) or The Smell of Undead (Horde) &gt; Hunting Lesson: Spring Strider &gt; Allies in Val\'sharah &gt; Sharptalon Team Up &gt; Destructive Prey &gt; Hunting Lesson: Terror Larva &gt; The Uncongenial Faction &gt; Sharptalon Bonding &gt; Hunting Lesson: Auburn Ringtail &gt; Teamwork Lesson: Dresaron &gt; Hunting Lesson: Vale Flitter &gt; Teamwork Lesson: Xavius &gt; Sharptalon Team Rumble &gt; Sharptalon Reunion /script print(IsQuestFlaggedCompleted(44881)) Check out Falcosaur! - Obtaining Falcosaur Mounts, Pets, Toys by Purgatorywolf for an in depth guide which includes details on requirements and tips for completion of each quest for your mount.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (44943, 0, 0, 'Now That\'s Just Clawful! &gt;&gt;&gt;&gt;&gt; https://www.youtube.com/watch?v=kQuP4WeCn3g', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45019, 0, 0, '&lt;Your sharptalon hatchling has not been eating recently. It seems to be depressed. Perhaps it is time to return it to its place of origin?&gt;', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45032, 0, 0, 'Interacting with the quest giver has my character\'s responses as &quot;Um, what?&quot; I feel this pretty much sums up the entirety of this quest. Skip it, bad design, worse execution.(##RESPBREAK##)520##DELIM##Onyx1831##DELIM##', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45048, 0, 0, 'Poor game design = Having to watch a Youtube video to complete a quest', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45049, 0, 0, 'Make sure you are mounted when u talk to the guy and you can just fly into the goal!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45068, 0, 0, '-COMIC BOOK GUY- &quot;Worst quest ever!&quot; Honestly i\'m surprised how many ppl are having trouble on these quests. Look down and follow with ur mouse. Its a breeze. Personaly i wish wow would add more quests/activites that don\'t just involve choppin\' sum1\'s head off but actually having to use that head, or more precisely the brain inside that head. I for 1 grew up playing Kings Quest, Hand of Fate, and other games where u had to use ur noggin.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45069, 0, 0, 'And like the unmitigated !@#$%^&amp;s blizz has shown to be throughout this expansion, they\'ve &quot;fixed&quot; it so the most tolerable of kirin tor quests is once again bull!@#$. Ie, the macro doesn\'t work anymore since the barrels are untargetable. var lv_screenshots = []; var lv_videos = [{\"id\":113299,\"user\":\"JNasty\",\"date\":\"2016-12-04T11:23:56-06:00\",\"videoType\":1,\"videoId\":\"M5k9y0HKerE\",\"type\":5,\"typeId\":45069,\"url\":null,\"caption\":\"World of Warcraft Barrels o\' Fun Azsuna World Quest Guide\",\"sticky\":1},{\"id\":115549,\"user\":\"eagleeye1975\",\"date\":\"2017-01-03T12:48:37-06:00\",\"videoType\":1,\"videoId\":\"uBNUzw7FAec\",\"type\":5,\"typeId\":45069,\"url\":null,\"caption\":\"Video with a few tips on how to do this quest better and more effectively.\"},{\"id\":123896,\"user\":\"Mypciscraze\",\"date\":\"2017-05-02T15:39:18-05:00\",\"videoType\":1,\"videoId\":\"SxlFcBBZfEY\",\"type\":5,\"typeId\":45069,\"url\":null,\"caption\":\"Barrels o\' Fun World Quest Azsuna\"}]; var g_pageInfo = {\"type\":5,\"typeId\":45069,\"name\":\"Barrels o\' Fun\"}; WH.Layout.set({breadcrumb: [0, 3, 14, 7334]}); //]]> // Links Barrels o\' Fun &nbsp; Game Completed &nbsp;( 1 )', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45070, 0, 0, 'I gather from what Phazed said below that there are supposed to be four rounds in the game. I was on round seven when I wondered how long this would go on. Tried log/log and started again. That worked. Cute game when it\'s working.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45071, 0, 0, 'It appears that Patch 7.2 has made it impossible to target any barrel with the so very useful macro - now you have to actually track the highlighted barrel. On the plus side, you do not have to get the 5 barrel test right as long as your overall score gets to the right level eventually.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45072, 0, 0, 'The macro does not work anymore in patch 7.2. We will need the addon Barrels o\' Easy instead.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45125, 0, 0, 'Quit fooling around and help me with this ritual!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45145, 0, 0, 'As promised, here is the crescent key that will open my family\'s lockboxes, though nothing of value remains. I trust whatever you find you\'ll deliver to Delas? Our ancestor\'s things, whatever their worth, should remain in our family.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45176, 0, 0, 'Why does Illidan\'s spirit disappear after release ? It should be there but wasn\'T on the map either.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45188, 0, 0, 'This quest seemingly can no longer be completed as Karlain isn\'t standing with the others anymore and is seemingly according to the quest marker, in the ground inside the building, somewhere you can never go. https://i.imgur.com/919uTeN.png', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45190, 0, 0, 'Karam Magespear awaits you on the Broken Shore, at the entrance to a cave, coordinates are 56.4 27.2 . TomTom: /way Broken shore:broken isles 56.4 27.2 Karam Karam Magespear - www.youtube.com/watch?v=0gjTb9gQ4tI', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45193, 0, 0, 'If you see a yellow exclamation mark in Broken Shore and can\'t find the quest giver, he\'s in the cave where you did the previous quest, Runes of Rending . /way 56.61, 27.20 I didn\'t talk to him after I did the rune walk, and then spent 2 weeks not being able to find him. Many thanks to the game master who hinted at the right direction :-)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45317, 0, 0, 'Just to clarify, starting and completing Order Hall missions using the Legion Companion app, works fine for the quest.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45343, 0, 0, 'It has been brought to my attention that a rather curious contagion is spreading through a small coastal region within Highmountain. The local tribes have abandoned the area for fear of catching this ailment that currently has no known cure. One of our own was traveling through the area when her companion fell ill. She has requested the Conclave\'s assistance. Seek her out, High Priest, and do whatever you can to stop this sickness from spreading.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45439, 0, 0, 'Murkidan DEFINITELY needs to fly with you on little green or purple demon wings like Murgulis does during this quest.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45540, 0, 0, 'Waypoint for entrance to Wailing Caverns /way 39.93 69.82', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45559, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45812, 0, 0, 'Have we gained ground?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45833, 0, 0, 'Straighten up, Shadowblade. We\'ve got work to do.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45839, 0, 0, 'Note that for this &quot;Assault on Stormheim&quot; invasion quest Vethir is at (90 11) not at his usual spot at cullens post.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45862, 0, 0, 'Are you ready?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45866, 0, 0, 'I would assumthat with Patch 7.3, I no longer have to do this questline? My artifact is completely maxed out with 7 levels already in my Agility circle.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (45910, 0, 0, 'While we have already given you what power we can, we would like to present to you a... cosmetic... upgrade to your artifact. On behalf of the Council of Six, Dalaran, and Azeroth, we thank you again, &lt;name&gt;.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46000, 0, 0, 'Use the Control Crystal to activate the Soulstone!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46072, 0, 0, 'If you don\'t get the completion from killing Golgranoth, and you\'re not in a raid, try pulling him down the hill a little. It won\'t count if you\'re out of the quest area - he\'s almost standing right on the edge of it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46116, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46184, 0, 0, 'If you have TomTom, then just type /way 55.4 45.4 Gelgothar He is just a short walk away from the flight master and very easily soloable.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46185, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46308, 0, 0, 'If like me you forget every time the way to the lighter, it\'s a small fel fire (looks like a teepee style camp fire but green) out the cave at the top of the stairs.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46322, 0, 0, 'Finally... my time to shine. Let\'s do this right.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46337, 0, 0, 'Either I got a bug somehow, or the requirements for you class mount have been lowered. I have my mount on...seven or eight classes now? And every time I\'ve had to complete both my order hall campaign and the broken shore campaign (Breaching the Tomb). But this time, to my surprise, I was given the golden letter quest right after finishing Champions of Legionfall (the quest to get your ilvl 850 order hall follower). I\'m also on the quest Shard Times, the one to give khadgar 2500 nethershards. It would seem the last 8 steps of the Legionfall campaign aren\'t required anymore (the sentinax, killing the rares, doing the 8 WQs, etc.) which was the most annoying part in my opinion. I\'m thankful for the relaxed requirements but I kinda wish it had happened sooner.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46338, 0, 0, 'Well? What did Ari think?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46749, 0, 0, 'This does not require Level 110. var lv_screenshots = [{\"id\":649021,\"user\":\"Rantsi\",\"date\":\"2017-08-14T15:03:10-05:00\",\"width\":601,\"height\":782,\"type\":5,\"typeId\":46749,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":390563,\"user\":\"gtulgar1903\",\"date\":\"2025-11-09T17:05:21-06:00\",\"videoType\":1,\"videoId\":\"gWFDd2x2MoI\",\"type\":5,\"typeId\":46749,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":46749,\"name\":\"Supplies From the Wardens\"}; WH.Layout.set({breadcrumb: [0, 3, 14, 7334]}); //]]> // Links Supplies From the Wardens Speak with Marin Bladewing in Azsuna for your reward. {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46752, 0, 0, 'Step 1: Kill the engineers to get 3 power cores Step 2a: If you have flying, fly into the floating orbs to charge the power cores. Go to step 4 Step 2b: If you don\'t have flying, walk onto the glowing green circles in the area and they will shoot you into the air Step 3: Use your extra action button to activate DH wings while in the air and glide through the orbs to charge the power cores. Repeat step 2b until fully charged. Step 4: You\'re done!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46787, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46935, 0, 0, 'This device appears to be used to relay messages to the large demon ship up above. Unfortunately, it is cracked and unresponsive. Perhaps someone at Deliverance Point will know more about these beacons.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (46947, 0, 0, 'Upon completion of this quest you will gain: 500 reputation with Armies of Legionfall See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(46947)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(46947))\");', 0);
