INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (47148, 0, 0, 'Even I could not foresee the strange ways in which you would fight your enemies &lt;name&gt;.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (47251, 0, 0, 'it is started by A Slightly More Urgent Letter from the Timewalkers', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (47495, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (47645, 0, 0, '&lt;The scroll pieces combine to form a tattered, but readable message:&gt; The time is nigh. The invocation will take place above the azure shrine. The void will swallow the bronze dragon. Our master has spoken, and we obey.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (48097, 0, 0, 'As of 11/23/23, this still seems bugged. I get the right color mixture as each of the 2 doors (for me it was purple left door, orange right door, green final chest. But I can\'t enter either door with the right color. :( Also any suggestions about leaving and coming back doesn\'t matter. So if the world quest is up - you cannot do the original quest. You\'ll have to wait till the world quest is NOT up to do it - it appears.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (49068, 0, 0, 'Upon completion of this quest you will gain: 75 reputation with 7th Legion 75 reputation with Zandalari Empire See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(49068)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(49068))\");', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (49077, 0, 0, 'If you abandon this quest, the quest item will be deleted and you will have to acquire it again.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (49266, 0, 0, 'It fills me with hope that we have found allies such as you.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (49788, 0, 0, 'Mastering the whispers requires constant focus and discipline. Your dedication inspires all who bear the name ren\'dorei--for we have become children of the Void. You have learned many lessons here, but the time has come to venture beyond Telogrus Rift. Go to Stormwind, the heart of the Alliance. There, the king\'s ambassador will greet you and guide you along your journey. Azeroth must be defended. I can think of no one better suited to answer that call than you, $p.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (49806, 0, 0, 'What\'s this? A map?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (49813, 0, 0, 'Tales of your heroism have spread to the ends of Azeroth... and beyond. Your skills have been requested elsewhere. Will you travel through the Dark Portal, fighting the Burning Legion on the sundered world of Outland? Or will you fly north, joining the battle against the Lich King in Northrend? The choice is yours, adventurer.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (49846, 0, 0, 'I chose Pandaria not because I liked the questing there, but because the ore over there sells fairly well still and of course mining gives fine XP.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (49860, 0, 0, 'I was already in Northrend as a level 77 Death Knight. I didn\'t really like Northrend so I chose to go to Outland to Shadow moon Valley. I\'ve done a few quests here already and still didn\'t get anything. What gives Blizzard?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (49864, 0, 0, '&lt;name&gt;! You have been called upon once again to assist the Alliance in matters of great import. Will you assist the Alliance\'s efforts against Deathwing and the Twilight Hammer? Or will you fly south to Pandaria, claiming its resources before the Horde does first? Make your choice and head into battle!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (50091, 0, 0, 'Hi all I present Fighting With Fire quest chain. Part of Drust Do It. See Video if need it for this quest - Video Village Repair . Quest Name: Start and description Finish 1. To Falconhurst! Inquisitor - Meet Inquisitor Cleardawn outside of Falconhurst. Inquisitor Cleardawn 2. Breaking Hag Inquisitor Cleardawn - Kill 15 Briarwood Creatures and Witches. They are all over Falconhurst. Inquisitor Cleardawn will move to Falconhurst. Inquisitor Cleardawn 3. Hold The Barricade! Inquisitor Cleardawn - Speak with Inquisitor Cleardawn and defend barricades. You will need to kill Briarwood Siegebreaker . Inquisitor Cleardawn 4. So Long, Sister Inquisitor Cleardawn - You need to kill Sister Noella Briarwood Is on southwest in house. Leandro Royston 5. Village Repair Auto START - Get to 100 %. You getting 10% for Large Fetish Destroyed Credit for small 2% for mobs 2%. All in Falconhurst. AUTO FINISH 6. A Missing Master Marten Webb - You need to found Warren Ashton He is in basement in house on north. Warren Ashton 7. Curiously Strong Warren Ashton - Use Frost Potion to cut of 20 fire in Falconhurst. When you will finish Warren Ashton will be out side same house. Warren Ashton 8. A Weapon of Old Warren Ashton - You need to help him to create Liquid Fire Flask . Before start speak with him. YOu will need to use correct ingredients just read for what He is asking and use that one. He will ask you 6 times. ingredients: Sulfur Saltpeter , Volatile Sap and Hearthbloom . Warren Ashton 9. Fighting With Fire Warren Ashton - Yu need to kill 3 Briarwood Bulwark ( thay are on north. You can use Liquid Fire Flask this is stuning and sets fire to enemies. After you will finish this Quest You will Reach part of Drust Do It. . Marten Webb . Thank You i Hope that Help You var lv_screenshots = [{\"id\":785715,\"user\":\"Perothvius\",\"date\":\"2018-09-1