INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (50577, 0, 0, 'If this quest bugs, return to the Zul\'jan Ruins island, then proceed back across the water to the hill. It may simply be a matter of leaving the WQ zone and returning. Yes, it bugged on me. I did this back to ZR and return to the hill, and all was OK. It may bug if someone is doing the quests on that hill. You can get the Skyterror kills sharing with those questing. var lv_screenshots = []; var lv_videos = [{\"id\":141687,\"user\":\"varenne\",\"date\":\"2018-06-30T18:51:41-05:00\",\"videoType\":1,\"videoId\":\"mFYxG2SX7_g\",\"type\":5,\"typeId\":50577,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":50577,\"name\":\"Unaccounted For\"}; WH.Layout.set({breadcrumb: [0, 3, 15, 8500]}); //]]> // Links Unaccounted For &nbsp; Primal Skyterror slain &nbsp;( 10 ) &nbsp; Injured Darkspear Scout rescued &nbsp;( 6 )', 0);
