INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (51379, 0, 0, 'You only have to be near a party member who get\'s all the orbs and you\'ll still get it done. Happened to me :)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (51404, 0, 0, 'Did it 3 times now, first i kind of believed in the /hug method. But then today i did the quest once more without hugs, just make sure your character touches the blue tip so no spark can jump over, sure works.', 0);
