INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (51455, 0, 0, 'The four pools are regular bodies of water, don\'t expect something glowing or fancy. They show clearly on your map once you are at the Tidesage Council. Your location will also change to Fonts of Cleansing which confirms you are at the right location. Nothing special, just jump down where you see water once you\'re there.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (51475, 0, 0, 'Brutosaurs are the happiest creatures in WoW, so happy that a Bunch of Wild Animals come to hang near it and not even attack it', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (51565, 0, 0, 'As of 10/26/2018 this quest is horribly bugged. Despawns … walking in out sometimes respawns it but so far nothing to get it to stay to completed. Beetles despawn as soon as they quest pops. At nearly 5am eastern … just gonna call it a night.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (51577, 0, 0, 'There are plenty of mobs on the north side, just head for the fires. The harpoon launchers are more difficult, but the north side is more effective. var lv_screenshots = []; var lv_videos = [{\"id\":152376,\"user\":\"Mypciscraze\",\"date\":\"2018-09-16T06:23:23-05:00\",\"videoType\":1,\"videoId\":\"R7u2MpxAJk8\",\"type\":5,\"typeId\":51577,\"url\":null,\"caption\":\"Defending the Academy World Quest Tiragarde Sound Battle for Azeroth World Of Warcraft\",\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":51577,\"name\":\"Defending the Academy\"}; WH.Layout.set({breadcrumb: [0, 3, 15, 8567]}); //]]> // Links Defending the Academy &nbsp; Hold back the Horde &nbsp;( 1 ) &nbsp; Fallen Marine slain &nbsp;( 25 ) &nbsp; Horde Spiritcaller slain &nbsp;( 25 ) &nbsp; Luske Sunmane slain &nbsp;( 13 ) &nbsp; Batrider Swales slain &nbsp;( 13 ) &nbsp; Deathstalker Infiltrator slain &nbsp;( 25 ) &nbsp; Players slain &nbsp;( 10 ) &nbsp; Horde Wyvernrider slain &nbsp;( 13 ) Marine Dog Tags &nbsp;( 20 ) WH.ge(\'icon-list-icon1\').appendChild(g_items.createIcon(160480, 0, 20, null, null)); {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (51584, 0, 0, 'Hi all You need to get azerite to 100%. How ? Kill mobs and on them body use Heart of Azeroth to absorbing Azerite. Bigger mobs more azerite. See My Video If need it - https://youtu.be/uXGdk6_a4m4 Hope that Help You.', 0);
