INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (51820, 0, 0, 'In this quest you cleanup oil spills, wash oil covered birds and kill Venture Co. adds. It is a sad reminder of what happens in the real world. Please don\'t litter and respect wildlife :) var lv_screenshots = [{\"id\":1268809,\"user\":\"auryunderground\",\"date\":\"2026-02-02T23:43:55-06:00\",\"width\":1600,\"height\":900,\"type\":5,\"typeId\":51820,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":151302,\"user\":\"Mypciscraze\",\"date\":\"2018-09-02T16:47:41-05:00\",\"videoType\":1,\"videoId\":\"ab420QAnTY8\",\"type\":5,\"typeId\":51820,\"url\":null,\"caption\":\"Oily Mess World Quest Stormsong Valley Battle for Azeroth World Of Warcraft\",\"sticky\":1},{\"id\":156223,\"user\":\"Ruiaxe\",\"date\":\"2018-11-23T13:33:50-06:00\",\"videoType\":1,\"videoId\":\"VSnqoYbyn3Q\",\"type\":5,\"typeId\":51820,\"url\":null}]; var g_pageInfo = {\"type\":5,\"typeId\":51820,\"name\":\"Oily Mess\"}; WH.Layout.set({breadcrumb: [0, 3, 15, 9042]}); //]]> // Links Oily Mess &nbsp; Coastline cleaned &nbsp;( 1 ) &nbsp; Venture Co. Firestarter slain &nbsp;(20) &nbsp; Venture Co. Firestarter &nbsp;( 1 ) &nbsp; Venture Co. Firestarter &nbsp;( 1 ) &nbsp; Venture Co. Firestarter &nbsp;( 1 ) &nbsp; Venture Co. Firestarter &nbsp;( 1 ) &nbsp; Venture Co. Firestarter &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Venture Co. Oiler slain &nbsp;( 13 ) &nbsp; Oil Drums collected &nbsp;( 17 ) &nbsp; Oil Drums collected &nbsp;( 17 ) &nbsp; Photographers slain &nbsp;(25) &nbsp; Venture Co. Reporter &nbsp;( 1 ) &nbsp; Venture Co. Mechanic &nbsp;( 1 ) &nbsp; Venture Co. Muscle &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Sandbills cleaned &nbsp;( 10 ) &nbsp; Pest Remover Mk. II slain &nbsp;( 4 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"