INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (52198, 0, 0, 'I might also add for those confused by the location of this WQ that it\'s in Stormsong NOT Nazamir where the tracker always seems to lead me. This has been a weird bug for a long, long time and has fooled me before. Why the tracker points to someplace in Nazamir and not Stormsong (for alliance players at least) is a mystery. I have reported this odd bug numerous times but as of today it still points to Nazamir instead of Stormsong.', 0);
