INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (52243, 0, 0, '&quot;What’s that you say? You haven’t played for a while and are super excited by all the new content... but your toon is wearing BoE greens from three expansions ago? Don’t worry, we’ve got just the catch up mechanism you need!&quot; &quot;Rest assured that in your absence, we’ve taken all your fellow players’ constructive criticism to heart (and we’ve been doing this for fourteen years, so there’s been a lot * lol *)… and that’s why this world quest involves hunting X-number of stealthed mobs and looting Y-number of items (with a sub-50% drop rate), just like the old days! WELCOME BACK AND HAPPY QUESTING!&quot; &quot;Missed ya\' * smooch *&quot; Blizz XoXoX var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":52243,\"name\":\"Fuel for the Demolishers\"}; WH.Layout.set({breadcrumb: [0, 3, 1, 148]}); //]]> // Links Fuel for the Demolishers Elemental Pitch &nbsp;( 6 ) &nbsp; Darnassian Scout slain &nbsp;( 7 ) WH.ge(\'icon-list-icon1\').appendChild(g_items.createIcon(161436, 0, 6, null, null)); {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} // See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(52243)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(52243))\");', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (52244, 0, 0, 'The Darkshore pre-patch quests actually yields ilvl 210 items called spell-splintered X. Apparently this catch-up gear has been buffed to 210 from the announced 195 ilvl. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":52244,\"name\":\"Stop the Drilling\"}; WH.Layout.set({breadcrumb: [0, 3, 1, 148]}); //]]> // Links Stop the Drilling &nbsp; Bilgewater forces slain &nbsp;(7) &nbsp; Bilgewater Enforcer &nbsp;( 1 ) &nbsp; Bilgewater Rigger &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Oil Pump disabled &nbsp;( 3 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} // See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(52244)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(52244))\");', 0);
