INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (52278, 0, 0, 'Sanotehu\'s &quot;3 Strider Strat&quot; below used to work for me every time but now it doesn\'t, not sure why. Here\'s a slight update that does the trick, every time so far: EDIT: Failed on the 9th time I used it, so RNG is a factor as usual Aqua Strider (1,2,2) Eternal Strider (1,2,2) Mirror Strider (1,1,2) Aqua Strider: Pump Pump Cleansing Rain (Overwrite Darkness, 1st strider dies) Eternal Strider: Water Jet (Azerite Slime dies -- may need another Water Jet) Pump Pump Water Jet Water Jet (Azerite Geode dies) Water Jet (2nd strider dies - another Water Jet if you last another turn) Mirror Strider: Pump Pump Healing Wave Water Jet Water Jet (Azerite Elemental dies)', 0);
