INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (52455, 0, 0, 'The following spoiler tag contains the rematch code, with fight instructions for this fight. It uses the following pets: Clockwork Gnome , Lil’ Bling , and Ikky This strategy came from Jessail on Xu-Fu\'s Pet Battle Strategies . If you don\'t know how to use the Rematch addon have a look at the Wowhead guide I wrote, which also includes the Rematch code for this and all BGA Pet Battle World quests (so you can import all the teams and fights at once rather than one at a time). Unbreakable:49SV:111B8L:1115198:11181FS:N:Strategy added by Jessail\\n\\nTurn 1 Build Turret\\nTurn 2 Switch to Lil\'Bling\\nTurn 3 Make it Rain\\nTurn 4 Switch to Ikky\\nTurn 5 Flock', 0);
