INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (52784, 0, 0, 'In Shadowlands I somehow managed to get the quest to pop after dying , which makes absolutely no sense. In fact, even in party I managed to get zerged, and the quest didn\'t fail. Call me insane (which title I do have) but I abandoned the quest considering this is just not how this is supposed to work and I can\'t find any honor in it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (52786, 0, 0, 'if you fail the quest, you have to abandon it and wait to get it again or it resets someway?', 0);
