INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (53497, 0, 0, 'https://www.youtube.com/watch?v=WUOtCLOXgm8 The one thing I appreciate in WoW is cultural references. From the mundane (Left Shark) to the historical (like this song), WoW, despite my many beefs with the company direction, has always managed to pull out some of the best when they name their quests. It is my hope, as a child at the time many of these Queen songs were popular, that they will inspire the younger generation who never heard them. I\'m guessing these quests will go away when BfA launches, and that\'s a shame. There is so much throwaway music these days, and songs from groups like Queen and others of that time prove they don\'t have to be. Forget your autotuning, this is the real thing.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (53498, 0, 0, 'Sadly, the Lunar Wards in this quest confused me far more than they should have. For those like me, the Lunar Wards you are to destroy are not the green portals that you cannot interact with. The Lunar Wards are cement braziers with a little white/blue aura under them (and a blue flame and moon floating above them before destroyed) that are closer to the edges of the quest area. They can be interacted with and may even have some Priestesses of the Moon around them. I found them at: /way 48.70 18.74 /way 48.75 21.01 /way 49.76 22.56 /way 51.33 22.96 *This was a pre-BfA world quest event that took place in the weeks before the launch, so this information probably has little--if any--value now beyond historical. :D Edit: added locations. *Later Edits: Updated information.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (53502, 0, 0, 'Another world... another time... this is an age of wonder.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (53520, 0, 0, 'Not a well-made quest at all. The barrels are too few &amp; spaced too far apart, and with so many players doing the world quests at the same time it takes a lot of swimming around looking for barrels &amp; waiting for more to respawn &amp; hoping you get to them before another player does. Because when one player detonates a barrel, it disappears for everyone.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (53550, 0, 0, 'In my experience people do not like to be driven from their homes. While normally we would crush them with the might of the Horde, we do not have time to carry out a lengthy campaign against these creatures. They will look to their leaders for hope, inspiration, and guidance. They will find none. You are the instrument of my will, &lt;name&gt;. Make them submit to it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (53552, 0, 0, 'Battle for Azeroth World Quests Overview $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (53668, 0, 0, 'Our goblin friend assures me he is able to expand our travel network as long as we hold key positions. Looks like we\'ve got our work cut out for us.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (53711, 0, 0, 'If you have only 3 tasks on the map and you do not know where to find the last one, check the map of Boralus', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (53886, 0, 0, 'Upon completion of this quest you will gain: 75 reputation with The Honorbound 75 reputation with Talanji\'s Expedition WH.Wow.Quest.setupScalingRewards({\"minLevel\":10,\"maxLevel\":10,\"xp\":{\"multiplier\":1,\"levels\":{\"10\":2125}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":0,\"levels\":{\"10\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(53886)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(53886))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
