INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (54112, 0, 0, 'As a Horde Pandaren Monk to quote a certain former Blizzard employee: When will we get our true warchief back? Thankfully there are 5 invasion worldquests and I don\'t have to do that ever again. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":54112,\"name\":\"Mistweaver Nian\"}; WH.Layout.set({breadcrumb: [0, 3, 15, 8567]}); //]]> // Links Mistweaver Nian &nbsp; Mistweaver Nian slain &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (54143, 0, 0, 'Use the Grizzek Rocket Hop to get on top of the buildings. The spy gear and shadoweye scout are found on the walls and roofs.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (54162, 0, 0, 'Where the heck is the doggone boom-o-matic thing located? By all the quest NPCs on the hill overlooking a bunch of wrecked ships. Close to the top of the T in Talanji\'s Rebuke on the map', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (54689, 0, 0, 'Hard to see at first and in the dense, non-moving groups but any bulwarks will kill your little spirit guy, run into the packs of moving mobs and keep running around until 100%, then go blow up against one of the two pillars that make the end guy\'s barrier. You run back up again and detonate on him. Took a few times to realize but after this you can do it quite easily in two goes.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (55142, 0, 0, 'Welcome to Stormwind, &lt;race&gt;.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (55148, 0, 0, 'The Irradiated Elementals can be turned into Unstable Irradiated Elementals when you use the Supercollider on them.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (55343, 0, 0, 'I failed this world quest twice and couldn\'t figure out what I was doing wrong. It was a triangle and I was tracing it perfectly. Apparently I was going the wrong direction. It seems you have to follow the path that takes you through the group of tortollan children.', 0);
