INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (55794, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (55849, 0, 0, 'If you\'re impatient, you can kite Anodized Enforcers to the rig in order to break it (make sure to kite them right next to it ). The pneumatic crush ability of the enforcers damages the rig. Warning: it\'ll take quite a few enforcers to fully break the rig, I think ours took around 20, maybe 25). As soon as the Enforcer you kited there is aggroed to Larry you can run back to Junkwatt to grab another one.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (55901, 0, 0, 'Turning in a quest that you get for defeating a legendary pet for the first time will give you 20% progress.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (55970, 0, 0, 'If you are fighting alongside a mob of people spam the following macro: /tar Zanj\'ir Slaver /cast', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (55982, 0, 0, 'If mobs stop giving you credit, try changing elemental. Same mobs gave me 0, swiched-here we go. Quality!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (56021, 0, 0, 'For anyone as stupid as I was, the quest is to achieve a single match of 5 runes. Not to make 5 matches of runes in succession! I agree it\'s hecking dumb, but I honestly read the &quot;in a row&quot; as &quot;one after the other&quot;.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (56022, 0, 0, 'To unlock these wq you have to find Silver Knife which can be found in all the arcane chest in Nazjatar', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (56050, 0, 0, 'Hey, not sure if anyone reads this, but when filling the Weekly bar during PvP Event: Battle for Nazjatar , you can activate the toy N\'lyeth, Sliver of N\'Zoth in order to be able to kill the guards of your own faction, which will give you 5% each as well. These do respawn. I usually fly from spot to spot and kill them as soon as they respawn. Pretty helpful when you dont have much time and are in a full win-group with no horde enemies and want to finish during this Event.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (56078, 0, 0, 'The best strat is: 1. aggro a bunch of them and herd them up in a small space. 2. drop a pufferish 3. safety bubble', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (56185, 0, 0, 'I\'m currently neck level 60 and there\'s no quest available for me on the Earthen NPC, I guess it requires a higher one?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (56267, 0, 0, 'For those in The War Within looking to unlock the Whispers of N\'zoth content, know that you NEED to go to your faction hub in BFA (For Alliance: Harbormaster\'s office) and you\'ll find a letter on the table with a quest marker, called &quot; An Unwelcome Advisor &quot;. This is how to get Wrathion into the Chamber of Heart, so that you can start the questline to unlock the Ny\'alotha raid. Nowadays, you don\'t need Ashjra\'kamas, Shroud of Resolve to do the last two fights of the raid, Insanity no longer kills you. Good luck, and happy farming! var lv_screenshots = [{\"id\":1216097,\"user\":\"Rantsi\",\"date\":\"2025-03-14T03:12:04-05:00\",\"width\":1600,\"height\":900,\"type\":5,\"typeId\":56267,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":56267,\"name\":\"Whispers of N\'Zoth\"}; WH.Layout.set({breadcrumb: [0, 3, 15, -569]}); //]]> // Links Whispers of N\'Zoth Speak to Kalecgos in the Chamber of Heart. {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (5665, 0, 0, 'You will receive: WH.Wow.Quest.setupScalingRewards({\"minLevel\":10,\"maxLevel\":10,\"xp\":{\"multiplier\":0,\"levels\":{\"10\":355}},\"coin\":{\"rewardAtCap\":150,\"multiplier\":0,\"levels\":{\"10\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(5665)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(5665))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (5669, 0, 0, 'Upon completion of this quest you will gain: WH.Wow.Quest.setupScalingRewards({\"minLevel\":10,\"maxLevel\":10,\"xp\":{\"multiplier\":1,\"levels\":{\"10\":355}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":1,\"levels\":{\"10\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(5669)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(5669))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (56764, 0, 0, 'Players giving you grief? Can\'t see what\'s on your plate? Here are two solutions: Solution 1: The Solo Strategy (Guaranteed to Work) Stop watching your character eat the sausages on their plate, instead watch the vehicle action bar. This helps to not only ignore the other players who are blocking your vision, but also focuses your attention on a smaller part of the screen. While monitoring your choke bar make sure to press the buttons as the become available. Fast button pressing is not required during the actual competition as faster button mashing is likely to result in your character choking. Instead take it slowly and eventually you will win. This may still be frustrating to those that are impatient, however patience is indeed the key to this challenge. As for actually making it into the eating competition, fast mouse clicking is your ticket. Unfortunately there is no queue which means that everyone will be scrambling to get into the competition and sadly disrespecting one another as they push and shove to get ahead of one another. Solution 2: The Group Strategy (Not Guaranteed to Work) If all else fails you might be able to form a group for later in the two week holiday event to alternate taking turns to each earn your tokens. This can wind up with you taking an hour to ensure that each of the four players in your group receives enough tokens for the toy. This strategy can make the competition much less arduous as three players can afk while one wins their tokens. Sadly, this is not a guaranteed viable strategy as other players make still be swarming the competition later in the holiday. Take this strategy with a grain of salt and as a last resort. Don\'t give up! You can do this! And remember you are competing against other players, not NPCs. Sometimes you will be competing with highly skilled players while other times you will be the most skilled. Practice doesn\'t make perfect, but it does make you better!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (5706, 0, 0, 'You will receive: WH.Wow.Quest.setupScalingRewards({\"minLevel\":15,\"maxLevel\":15,\"xp\":{\"multiplier\":0,\"levels\":{\"15\":525}},\"coin\":{\"rewardAtCap\":300,\"multiplier\":0,\"levels\":{\"15\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(5706)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(5706))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
