INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (57205, 0, 0, 'I am not sure that this is a bug in the quest. I think it is so you can keep getting the buff you need to unlock sorrowbane. So you can keep trying without the world quest completing.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (57275, 0, 0, '&lt;Looking into the crystal, the light around you is slowly drowned in inky smoke. An imposing presence crushes down on you, whispering unintelligibly in your ear. Looking for the source, you see nothing, but the sensation grows. Your head begins to swim as the darkness deepens and the noise becomes deafening. Summoning all your willpower to steel your resolve... The light has returned, the noise silenced, and you stand with a humble crystal in your hand. Perhaps Wrathion knows more about it...&gt;', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (57359, 0, 0, '// new Listview({ data: lv_comments0, id: \'comments\', name: WH.TERMS.comments, parent: lkljbjkb574, tabOpts: {className: \'ugc-tab ugc-tab-comments\'}, tabs: tabsRelated, template: \'comment\', });new Listview({ data: lv_screenshots, id: \'screenshots\', name: WH.TERMS.screenshots, parent: \'lkljbjkb574\', tabOpts: {className: \'ugc-tab ugc-tab-screenshots\'}, tabs: tabsRelated, template: \'screenshot\', });if (lv_videos.length) { new Listview({ data: lv_videos, id: \'videos\', name: WH.TERMS.videos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); } if (window.lv_videos_english && lv_videos_english.length) { new Listview({ data: lv_videos_english, id: \'videos-english\', name: WH.TERMS.englishvideos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); }tabsRelated.flush(); //]]>', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (57443, 0, 0, 'Something that I haven\'t seen noted yet is that your dredger attacks the wreckage you toss it on to, and you\'ll get credit when that particular rubble wreckage dies/reaches 0.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (57590, 0, 0, '// new Listview({ data: lv_comments0, id: \'comments\', name: WH.TERMS.comments, parent: lkljbjkb574, tabOpts: {className: \'ugc-tab ugc-tab-comments\'}, tabs: tabsRelated, template: \'comment\', });new Listview({ data: lv_screenshots, id: \'screenshots\', name: WH.TERMS.screenshots, parent: \'lkljbjkb574\', tabOpts: {className: \'ugc-tab ugc-tab-screenshots\'}, tabs: tabsRelated, template: \'screenshot\', });if (lv_videos.length) { new Listview({ data: lv_videos, id: \'videos\', name: WH.TERMS.videos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); } if (window.lv_videos_english && lv_videos_english.length) { new Listview({ data: lv_videos_english, id: \'videos-english\', name: WH.TERMS.englishvideos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); }tabsRelated.flush(); //]]>', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (57737, 0, 0, 'This is entirely circumstancial and will appear wrong and incorrect. I myself think that something went wrong here and that this shouldn\'t have happened the way it did and I really can\'t explain it. Tried this quest today, with warmode off. Still remember it having been fixed and working like a charm, with respawns every 20-30 seconds with like a dozen players in the region. (Never much more since the fix, because most people managed to get the quest done relatively quickly.) Today, I saw a bunch of shadow-versions of the villagers you need to rescue, there were about 2 dozen players in the area and the respawn was abysmal. It took me a solid 3 minutes of flying near the portside of the village to confirm that the villagers actually still existed. (It was the one that spawns in the alleyway) Never saw any of them in the port area. Guildmates reported doing the quest in less than a minute in a group, less than two minutes solo. They had warmode active, though. Still, no respawns for several minutes = no respawns for several minutes, that should apply to them aswell, so why did it work for them and not for me. After being frustrated for ~10 minutes, I went back to Orgrimmar and turned Warmode on. Flew back there, villagers everywhere. Rescued 4 of them, turned around, first one was already respawned. Took me less than 2 minutes to finish it, with more respawns occuring immediately after. Obviously, way less players present, because everyone managed to finish the quest practically immediately. And that sounds entirely wrong and like observation bias, and it might be... but there were still no realistic number of respawns while I was there with warmode off. I think they fixed it so that larger numbers of players mean faster respawns, but it just wasn\'t happening that way. Not sure whether we managed to reach critical mass or something, but it seems as though the large number of players meant fewer respawns. Or maybe the NPCs were broken and they didn\'t respawn because of that, no idea. So yeah, if anyone else can\'t finish it, maybe try turning Warmode on or off, see if that changes anything. Worked for me when it really shouldn\'t have made a difference.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (58144, 0, 0, 'If you are a Druid , do not attempt to turn them in while in travel form. It can bug the WQ. Make sure to unshift before you get to the soul turn in.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (58146, 0, 0, 'Welcome to Stormwind, &lt;race&gt;.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (58273, 0, 0, 'Some useful data that I got with my rogue. You can attack people with low level 110-120. If after you got the quest you can change the zone (I did between the kultira zones) to get you out of the assassin\'s debuff of the alliance or horde and if you kill only your faction then you don\'t get the bounty. And finally if you are alone and you cant find help you can try to be rogue and wait for a fight between the factions and when they are distracted you throw a dagger and you disappear before they attack you and give you the credit when the one you attacked dies', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (58274, 0, 0, 'I had the Quest with the toy in the backpack when i hearthstoned, i lost the Quest &amp; the toy :/', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (58436, 0, 0, 'Continue in this manner, and our people will continue to advance at a rapid pace. There is so much left to discover! Continue to learn and grow, &lt;name&gt;!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (58490, 0, 0, 'Does anybody know if this WQ is only visible to players with the necrolord covenant? Asking because I have not seen this wq and I\'ve been checking the last 2 weeks. Nirvaska the Summoner is the last rare I need for Shadowlands Voyager .', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (58596, 0, 0, 'To anyone frustrated by not seeing this quest yet, I\'ve been looking everywhere and saw this comment from a mod in the WoW support: &quot;While I can’t say much, because this would be heading into what is considered a game hint, there do appear to be additional requirements that you’ll need to discover.&quot; I believe requirements have changed and we likely need to unlock/build the next tier of the Stitchworks to unlock this.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (58975, 0, 0, 'Please keep the following in mind when posting a comment: Your comment must be in English or it will be removed. Unsure how to post? Check out our handy guide ! You might want to proof-read your comments before posting them. Please post questions on our forums for quicker reply. Post a Comment You are not logged in. Please log in or register an account to add your comment. Simply browse for your screenshot using the form below. Screenshots containing UI elements are generally declined on sight, the same goes for screenshots from the modelviewer or character selection screen. The higher the quality the better! Please review our Screenshot Guidelines before submitting! You are not logged in. Please log in to submit a screenshot. Simply type the URL of the video in the form below. URL: Supported: YouTube only Title: Optional, up to 200 characters', 0);
