INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59317, 0, 0, 'Bug for me too: 1. Abandon quest. 2. Relog. 3. Take the quest and this time it works.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59599, 0, 0, 'I don\'t know if this quest is bugged or what but could not get credit whatsoever for killing the dudes there nor animating the gargoyles.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59601, 0, 0, 'Upon completion of this quest you will gain: 125 reputation with The Ascended WH.Wow.Quest.setupScalingRewards({\"minLevel\":60,\"maxLevel\":60,\"xp\":{\"multiplier\":1,\"levels\":{\"60\":8165}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":0,\"levels\":{\"60\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(59601)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(59601))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59615, 0, 0, 'Are you willing to do this?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59643, 0, 0, 'I didn\'t see this mentioned, but when I did this WQ, it didn\'t count towards my covenent\'s &quot;Training in Revendreth&quot; quest - the one where you have to do 3 WQs with your trainee. Not sure if this is unintentional or intended as I\'ve only tried it once.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59680, 0, 0, 'This quest is a royal pain in the ass if you have a minion or a pet. Had to turn off taunt and growl, because if the mob died outside the wretched bell range, you don\'t get credit. And then there\'s the fact the bell expires just before the mob dies. Add to the woes a lobsided server where there are no mobs that aren\'t tagged, I tell this stupid quest, not today!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59743, 0, 0, 'Aren\'t world quests supposed to be fun and quick to do? I\'ve already encountered way too many of these seemingly randomly generated world quests that have never been checked once before rolling into retail. Save yourself the headache and just skip these when you get them, until they\'re tuned. Any reward it may give isn\'t worth it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59771, 0, 0, 'The spawn rate on Voidbound Defenders is very low. Your best bet is to go to the edges away from most players and camp the spawn of one after you find it - or a corpse of one.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59778, 0, 0, '// new Listview({ data: lv_comments0, id: \'comments\', name: WH.TERMS.comments, parent: lkljbjkb574, tabOpts: {className: \'ugc-tab ugc-tab-comments\'}, tabs: tabsRelated, template: \'comment\', });new Listview({ data: lv_screenshots, id: \'screenshots\', name: WH.TERMS.screenshots, parent: \'lkljbjkb574\', tabOpts: {className: \'ugc-tab ugc-tab-screenshots\'}, tabs: tabsRelated, template: \'screenshot\', });if (lv_videos.length) { new Listview({ data: lv_videos, id: \'videos\', name: WH.TERMS.videos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); } if (window.lv_videos_english && lv_videos_english.length) { new Listview({ data: lv_videos_english, id: \'videos-english\', name: WH.TERMS.englishvideos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); }tabsRelated.flush(); //]]>', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (59836, 0, 0, 'The Unbound Deathwalker make this more tedious then the other &quot;Battles Won Long Ago&quot; quests.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60231, 0, 0, 'The queen at the top respawns roughly every 5 to 10 minutes. Don\'t bother going for this WQ if you\'re on a shard which favours the opposing faction. If you\'re on a stealth class, you can just AFK camp the queen at the top for 25 % progress on each kill. There are way too few other mobs for everyone to be satisfied.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60455, 0, 0, 'You seem different, somehow.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60459, 0, 0, 'I did layer 3 on my DK yesterday. got 150 from that layer. I\'m not sure but just like Soul Ash, it may well be that you get a cumulative amount for the layers below.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60475, 0, 0, 'Gather the 10 supplies, then convert to raid. You can then turn in to all NPCs the same day for all the achievement progress without actually completing the quest. Then convert back to party when you\'re ready to complete the daily.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60531, 0, 0, 'Unless Spider on the Wall Q is also available, getting to the Q area will break the bank in death costs unless you\'re very lucky. Poorly designed. This instance works in the same way as other Q\'s of this type, in so far as there is a limit on \'tags\' for each NPC. I must just have been quite lucky in other zones in being among the 1st 4 from faction to tag an enemy. Note: If the NPC name appears in grey, move on - it shows that enough players are already tackling it. As usual don\'t waste time if the other faction are taking down an NPC, wish they had faction specific realms (PVP excepted) it would make Q\'s a lot less of a pain.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60532, 0, 0, 'Re: WQ - If you for some reason can\'t find anyone to group with, or like me, can\'t fly yet and keep getting dropped from groups because people are jerks and don\'t want to wait for you to get to them, this IS soloable, though it will take a little bit of time. Go to the Dominance Keep Flight Master, then go around behind him and to the right. Follow the trail until you come to where the Tower Creepers (which will give you 1% each) and Shrieking Evedwellers (2%) are. Kill those until you reach 100%. Bonus: they\'re skinnable. var lv_screenshots = []; var lv_videos = [{\"id\":194646,\"user\":\"Mypciscraze\",\"date\":\"2020-12-14T01:44:54-06:00\",\"videoType\":1,\"videoId\":\"id2TidBN5SI\",\"type\":5,\"typeId\":60532,\"url\":null},{\"id\":194653,\"user\":\"BloodyBajaz\",\"date\":\"2020-12-14T05:43:14-06:00\",\"videoType\":1,\"videoId\":\"rrltUHDX8j0\",\"type\":5,\"typeId\":60532,\"url\":null},{\"id\":194673,\"user\":\"Jhaman\",\"date\":\"2020-12-15T02:51:20-06:00\",\"videoType\":1,\"videoId\":\"ugWR7WYfSqM\",\"type\":5,\"typeId\":60532,\"url\":null,\"caption\":\"Destroy the Dominant World Quest, Easy Solo\"}]; var g_pageInfo = {\"type\":5,\"typeId\":60532,\"name\":\"Destroy the Dominant\"}; WH.Layout.set({breadcrumb: [0, 3, 16, 10413]}); //]]> // Links Destroy the Dominant &nbsp; Dominance Keep disrupted &nbsp;( 1 ) &nbsp; T4 &nbsp;(13) &nbsp; Gor\'vul &nbsp;( 1 ) &nbsp; Harbinger Raan\'kul &nbsp;( 1 ) &nbsp; Towering Tombcarver &nbsp;( 1 ) &nbsp; Rockbreaker &nbsp;( 1 ) &nbsp; Second Talon Eviscera &nbsp;( 1 ) &nbsp; Voryis Soulbreaker &nbsp;( 1 ) &nbsp; Iryna the Disciplined &nbsp;( 1 ) &nbsp; Nurgash Muckformed &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; T3 &nbsp;(25) &nbsp; Essence of Desperation &nbsp;( 1 ) &nbsp; Living Blade &nbsp;( 1 ) &nbsp; Dominance Dreadblade &nbsp;( 1 ) &nbsp; Sinstone Construct &nbsp;( 1 ) &nbsp; Stoneborn Skystalker &nbsp;( 1 ) &nbsp; Great Granitefur &nbsp;( 1 ) &nbsp; Living Scepter &nbsp;( 1 ) &nbsp; Dominance Soulbender &nbsp;( 1 ) &nbsp; Nightwidow Horror &nbsp;( 1 ) &nbsp; Living Bulwark &nbsp;( 1 ) &nbsp; Stoneborn Steelwing &nbsp;( 1 ) &nbsp; Dire Evedweller &nbsp;( 1 ) &nbsp; Hewn Protector &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; T2 &nbsp;(50) &nbsp; Shrieking Evedweller &nbsp;( 1 ) &nbsp; Loyal Granitefur &nbsp;( 1 ) &nbsp; Carved Servant &nbsp;( 1 ) &nbsp; Petrified Servant &nbsp;( 1 ) &nbsp; Dutiful Laborer &nbsp;( 1 ) &nbsp; Unleashed Hatred &nbsp;( 1 ) &nbsp; Unfinished Granitefur &nbsp;( 1 ) &nbsp; Loyal Granitefur &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; T1 &nbsp;(100) &nbsp; Tower Creeper &nbsp;( 1 ) &nbsp; Mire Dredger &nbsp;( 1 ) &nbsp; Malevolent Minion &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Barrel &nbsp;( 50 ) &nbsp; Lantern 1 &nbsp;( 50 ) &nbsp; Lantern 2 &nbsp;( 50 ) &nbsp; Rose &nbsp;( 50 ) Disassembly Flag &nbsp;( 1 ) WH.ge(\'icon-list-icon1\').appendChild(g_items.createIcon(174110, 0, 1, null, null)); {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60533, 0, 0, 'You may find that the progression bar stops filling up, I was stuck on 81%. If this happens, fly away and return and it should start filling again. Hope this helps someone. var lv_screenshots = []; var lv_videos = [{\"id\":194894,\"user\":\"Mypciscraze\",\"date\":\"2020-12-17T01:46:25-06:00\",\"videoType\":1,\"videoId\":\"hLP1OOVN8As\",\"type\":5,\"typeId\":60533,\"url\":null,\"caption\":\"Terrors in Tirna Scithe World Quest Ardenweald Shadowlands WOW\"},{\"id\":194929,\"user\":\"BloodyBajaz\",\"date\":\"2020-12-17T06:51:25-06:00\",\"videoType\":1,\"videoId\":\"wjDzKsPe7JI\",\"type\":5,\"typeId\":60533,\"url\":null}]; var g_pageInfo = {\"type\":5,\"typeId\":60533,\"name\":\"Terrors in Tirna Scithe\"}; WH.Layout.set({breadcrumb: [0, 3, 16, 11510]}); //]]> // Links Terrors in Tirna Scithe &nbsp; Tirna Scithe cleansed &nbsp;( 1 ) &nbsp; T4 Credit &nbsp;(10) &nbsp; Oranomonos the Everbranching &nbsp;( 1 ) &nbsp; Shan\'ala, Lost to the Tangle &nbsp;( 1 ) &nbsp; Goregullet &nbsp;( 1 ) &nbsp; Estrik Drina &nbsp;( 1 ) &nbsp; Rootfingers &nbsp;( 1 ) &nbsp; Thrashspine &nbsp;( 1 ) &nbsp; Karon Ruz &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; T3 Credit &nbsp;(17) &nbsp; Dustwilt Acidmaw &nbsp;( 1 ) &nbsp; Agitated Mistfeather &nbsp;( 1 ) &nbsp; Will-o\'-the-Mist &nbsp;( 1 ) &nbsp; Hazebroken Guardian &nbsp;( 1 ) &nbsp; Oaken Crusher &nbsp;( 1 ) &nbsp; Dustwilt Scythehorn &nbsp;( 1 ) &nbsp; Boggart Mirelurker &nbsp;( 1 ) &nbsp; Fog-Frenzied Gladestalker &nbsp;( 1 ) &nbsp; Oakheart Soul-Eater &nbsp;( 1 ) &nbsp; Dustwilt Gorger &nbsp;( 1 ) &nbsp; Tangled Mistcreeper &nbsp;( 1 ) &nbsp; Mist-Maddened Wader &nbsp;( 1 ) &nbsp; Oakheart Nightscreamer &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; T2 Credit &nbsp;(34) &nbsp; Dustwilt Reaper &nbsp;( 1 ) &nbsp; Oakheart Drust-Taken &nbsp;( 1 ) &nbsp; Vile Wraith &nbsp;( 1 ) &nbsp; Shifting Boggart &nbsp;( 1 ) &nbsp; Vengeful Essence &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; T1 Credit &nbsp;( 100 ) &nbsp; Gorm Sac &nbsp;( 50 ) &nbsp; Mushroom - Int &nbsp;( 50 ) &nbsp; Mushroom - Agi &nbsp;( 50 ) &nbsp; Mushroom - Str &nbsp;( 50 ) &nbsp; Mushroom - Cleanse &nbsp;( 50 ) &nbsp; Barrel &nbsp;( 50 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60545, 0, 0, 'Logged into the Beta with a level 116 BfA char (transferred), who was scaled down to level 48. I got that quest right away.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60601, 0, 0, 'You will receive: Grateful Offering WH.ge(\'icontab-icon1\').appendChild(g_gatheredcurrencies.createIcon(1885, 1, \"2\"));', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60656, 0, 0, 'I\'m furious , I stepped out of bounds at 20/20 and it reset me to 0 fragments &gt;.&lt;', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60658, 0, 0, 'Upon completion of this quest you will gain: 125 reputation with Court of Harvesters WH.Wow.Quest.setupScalingRewards({\"minLevel\":60,\"maxLevel\":60,\"xp\":{\"multiplier\":1,\"levels\":{\"60\":8165}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":0,\"levels\":{\"60\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(60658)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(60658))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60659, 0, 0, 'So, another quest that\'s a pain to do if there are others doing it also! Shadowlands world quests are horrible!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60844, 0, 0, 'I believe that &quot;falling with style&quot; is a reference to Toy Story - where, being a toy, Buzz Lightyear wasn\'t actually flying but rather &quot;falling with style.&quot;', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60858, 0, 0, '100% The way to do this is looking top down. If you aren\'t sure about hitting the next flower then it\'s much easier to double back and hit it again. Completed WQ the first time I switch to this view.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60899, 0, 0, 'I managed to complete and get credit for this quest today, Nov 27. Go to NPC Zarkin and wait until he takes off with his group. Follow the group, and engage in the battles. As another poster said, he makes 5 stops, and you\'ll need credit for 5 stops to complete. If you die, or get lost, you can take up with the Hunt at any point in the cycle. To get credit for the stop, I think you have to be within the blue circle that forms at the end of each battle. Not sure whether you have had to tag or kill mobs, but the blue circle seems to be necessary.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60911, 0, 0, 'Please keep the following in mind when posting a comment: Your comment must be in English or it will be removed. Unsure how to post? Check out our handy guide ! You might want to proof-read your comments before posting them. Please post questions on our forums for quicker reply. Post a Comment You are not logged in. Please log in or register an account to add your comment. Simply browse for your screenshot using the form below. Screenshots containing UI elements are generally declined on sight, the same goes for screenshots from the modelviewer or character selection screen. The higher the quality the better! Please review our Screenshot Guidelines before submitting! You are not logged in. Please log in to submit a screenshot. Simply type the URL of the video in the form below. URL: Supported: YouTube only Title: Optional, up to 200 characters', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60929, 0, 0, 'Had my parachute fail to deploy after clicking the dismount button. Made an awful quest even more &quot;enjoyable&quot;.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60958, 0, 0, 'Upon completion of this quest you will gain: 125 reputation with The Ascended WH.Wow.Quest.setupScalingRewards({\"minLevel\":60,\"maxLevel\":60,\"xp\":{\"multiplier\":1,\"levels\":{\"60\":8165}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":0,\"levels\":{\"60\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(60958)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(60958))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (60972, 0, 0, 'Was almost done when I had an important phonecall so logged off. Came back to see I had to start over from scratch with charging it. Be weary of that.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61141, 0, 0, 'Want to get this over quickly? You don’t actually have to play with him. You can just taunt him. Take the skull, toss it next to you, away from him, and pick it back up. Move away in the cooldown timer, and repeat. If someone summoned Karaage, tap and slap for credit, after you pet Deathfang of course. Sound cruel? Well, welcome to hell, buddy.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61189, 0, 0, 'Great place to farm these really quickly is /way 61.80 49.65 Constant respawn rate For non-tomtom users: https://imgur.com/a/Gv1PfnO', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61337, 0, 0, 'man playing holy priest and the moment I healed Heraclor I aggroed like 30+ things and got mowed down so hard, even with fade :(', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61342, 0, 0, 'As of dragonflight can no longer do these as lvl 70, no quest credit for killing the mobs. Please report in-game bug', 0);
