INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61520, 0, 0, 'Upon completion of this quest you will gain: 125 reputation with The Ascended WH.Wow.Quest.setupScalingRewards({\"minLevel\":60,\"maxLevel\":60,\"xp\":{\"multiplier\":1,\"levels\":{\"60\":8165}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":0,\"levels\":{\"60\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(61520)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(61520))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61557, 0, 0, 'Just to add on to nighteye22\'s post. Had a character in its covenant since before 9.1, highlord\'s vision was flagged as incomplete. Simply zoning into oribos (in my case flying to maldraxxus for WB for renown) will flag you for completion, thus losing access to this quest if you have completed it (or were skipped ahead by the 9.1 quest catchup). Unsure if it is &quot;still&quot; in the game but unless you want to spin up a new wow account on your blizz account (I guess that would make you immune to quest skip maybe?) consider this quest obsolete.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61708, 0, 0, 'If you destroyed the clicky egg first like I did, just use the item to get credit for destroying the phylactery. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":61708,\"name\":\"Drawing Out the Poison\"}; WH.Layout.set({breadcrumb: [0, 3, 16, 11462]}); //]]> // Links Drawing Out the Poison &nbsp; Ride Grimshadow to the Flayedwing Nesting Grounds &nbsp;( 1 ) &nbsp; Phylactery of Arin\'gore found &nbsp;( 1 ) &nbsp; Phylactery of Arin\'gore destroyed &nbsp;( 1 ) &nbsp; Arin\'gore slain &nbsp;( 1 ) Phylactery of Arin\'gore &nbsp;( 1 ) WH.ge(\'icon-list-icon1\').appendChild(g_items.createIcon(174043, 0, 1, null, null)); {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61870, 0, 0, '3 pets with Scratch , Dodge , and Burrow . I use Spring Rabbit x2 and a Core Hound Pup . Also I\'ve used a team of Snowshoe Rabbit because of there speed and power. First I use Dodge , Scratch , then Burrow . Use abilities after they CD. Edit: The comment below saying it doesn\'t work is not true. I went back and tested the consistency of this pet strategy. It is foolproof with no RNG involved.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61874, 0, 0, 'Quest just keeps popping up even if accepted on my level 50, makes incredibly annoying while trying to start DF pre-patch for leveling 50-60.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61883, 0, 0, 'This team seems to work every time. Hermit Crab &gt; Dive &gt; Bubble &gt; Pinch Nexus Whelpling &gt; Arcane Storm &gt; Mana Surge Chrominius &gt; Howl &gt; Ravage', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61885, 0, 0, 'Mechanical Strat : Fairly reliable with 90% +- success rate. Attempted 10 matches with 1 fail when Rocko crit Iron Starlette with bodyslam and 1 win that happened early due to Iron Starlette crushing Rocko in 1 shot before Menagerie Custodian had a chance to join the battle. Matches lasted between 10-12 total rounds so it\'s fairly quick. Level 25 pets used and it is important if you will also be attempting Battle in the Shadowlands Ach which requires a full team of level 25 pets to complete. Microbot XD 2/2/2 Iron Starlette 1/2/1 (p/p breed used) Menagerie Custodian x/x/2 Microbot XD Turn 1 - Lock-On Turn 2 - Supercharge Turn 3 - Lock-On Turn 4 - Ion Cannon (Microbot dies) Iron Starlette P/P Turn 5 - Wind-Up Turn 6 - Toxic Smoke Turn 7 - Wind-up Turn 8 - Wind-up Turn 9 - Supercharge Turn 10 - Wind-up Menagerie Custodian Turn 11 - Ion Cannon Hope this helps!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61947, 0, 0, 'For anyone not max level, just be careful there are level 60 prowling kitties near the tamer. I found out the hard way. Also, this pet battle WQ did not count towards progression on Support the Court . Edit: As of 9th Dec hotfixes the pet battle quests now count for progression on several quests of this type.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (61948, 0, 0, 'Eerie Elementals (Very RNG dependent - If your first pet doesn\'t last into 1-2 rounds of second pet reset - mothballs are dumb - sometimes Geyser stuns first pet and brings in second, and that sometimes works great, so adjust according to cooldowns on Jademist Dancer) Jademist Dancer Jade Claw, Rain Dance, Geyser Fel Flame Burn, Scorched Earth, Conflagrate Lil\' Ragnaros Sulfuras Smash, Conflagrate, Son\'s of Flame Jademist Dancer Geyser Rain Dance (crit from this is key for next 2 hits) Jade Claw Jade Claw (Star Tail dies here from Geyser) Jade Claw until JadeMist Dancer dies or Geyser is up Fel Flame Scorched Earth (unless you have had 2 hits from Jademist Dancer - hold it for next round when he recasts Toxic Fumes Depending on health - if under 300 hp - use Burn if over 300 use Conflagrate if Needlenose is still alive Burn until dead (unless he casts Toxic Fumes - recast Scorched Earth) Lil Ragnaros Conflagrate (Scorched Earth should still be up - if Needlenose got Toxic Fumes up reset) Son\'s of Flame Sulfuras Smash if not dead yet', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62043, 0, 0, 'Didn’t see this mentioned here, so about anima. You of course want to buy anything you can and once you switch, sell it back. But they don’t welcome you back till you do the quest twice. Before you turn in the 2nd quest is when you want to buy whatever so you fan bring your anima with you. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":62043,\"name\":\"Prove Your Worth\"}; WH.Layout.set({breadcrumb: [0, 3, 16, -576]}); //]]> // Links Prove Your Worth Complete the task for the Kyrian. &nbsp; Complete Tasks in Bastion &nbsp;( 1 ) &nbsp; Rares &nbsp;(17) &nbsp; Herculon &nbsp;( 1 ) &nbsp; Sigilback &nbsp;( 1 ) &nbsp; Dionae &nbsp;( 1 ) &nbsp; Basilofos, King of the Hill &nbsp;( 1 ) &nbsp; Corrupted Clawguard &nbsp;( 1 ) &nbsp; Xixin the Ravening &nbsp;( 1 ) &nbsp; Malfunctioning Clawguard &nbsp;( 1 ) &nbsp; Baedos &nbsp;( 1 ) &nbsp; Aethon &nbsp;( 1 ) &nbsp; Wingflayer the Cruel &nbsp;( 1 ) &nbsp; Cloudfeather Guardian &nbsp;( 1 ) &nbsp; Demi the Relic Hoarder &nbsp;( 1 ) &nbsp; Bookkeeper Mnemis &nbsp;( 1 ) &nbsp; Fallen Acolyte Erisne &nbsp;( 1 ) &nbsp; Nemaeus &nbsp;( 1 ) &nbsp; Kill Credit: Rare Spawn - Bastion &nbsp;( 1 ) &nbsp; Unstable Memory &nbsp;( 1 ) &nbsp; Embodied Hunger &nbsp;( 1 ) &nbsp; Aspirant Eolis &nbsp;( 1 ) &nbsp; Nikara Blackheart &nbsp;( 1 ) &nbsp; Cloudtail &nbsp;( 1 ) &nbsp; Dark Watcher &nbsp;( 1 ) &nbsp; Enforcer Aegeon &nbsp;( 1 ) &nbsp; Collector Astorestes &nbsp;( 1 ) &nbsp; Echo of Aella &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Rare Elites &nbsp;(13) &nbsp; Selena the Reborn &nbsp;( 1 ) &nbsp; Kill Credit: Rare Elite - Bastion &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Treasures &nbsp;( 13 ) &nbsp; World Quests &nbsp;( 13 ) &nbsp; Daily Quests &nbsp;( 17 ) &nbsp; Dungeon Bosses &nbsp;(9) &nbsp; Ventunax &nbsp;( 1 ) &nbsp; Devos &nbsp;( 1 ) &nbsp; Blightbone &nbsp;( 1 ) &nbsp; Amarth &nbsp;( 1 ) &nbsp; Oryphrion &nbsp;( 1 ) &nbsp; Surgeon Stitchflesh &nbsp;( 1 ) &nbsp; Nalthor the Rimebinder &nbsp;( 1 ) &nbsp; Kill Credit: Dungeon Bosses - Bastion &nbsp;( 1 ) &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62058, 0, 0, 'If you see the incorrect Overseer you can do one of two things that may fix it: 1) Dismiss the vehicle you\'re in and pick a new one and run back to see OR 2) Relog or leave the world quest area and go back this should fix it and phase you into the correct location.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62059, 0, 0, 'I just completed this quest by doing rare elites and world quests in Maldraxxus. Upon returning to Oribos to turn in the quest I got no follow-up, but were instead told by the NPC to return at a later date. Apparently the Necrolords are going to &quot;discuss among themselves&quot; if I am worthy or not. I can only speculate that this means that I will be able to switch Covenants after reset - either daily or weekly.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62061, 0, 0, 'You must prove your worth to us again &lt;name&gt;. We have not forgotten your betrayal. Yet we know you seek penance. This task should prove your willingness to rejoin our ranks.', 0);
