INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62235, 0, 0, 'this quest isn\'t bugged. you have to lead an anima-starved creature to one of the coalesced anima orbs, kill it beside the orb, and then charge the allay crook. that will let you do the ritual after. just did it today, 12/28/2024. var lv_screenshots = [{\"id\":1063454,\"user\":\"Kromiska\",\"date\":\"2022-05-29T06:50:31-05:00\",\"width\":1600,\"height\":847,\"type\":5,\"typeId\":62235,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":191819,\"user\":\"Zhamant\",\"date\":\"2020-11-27T02:34:38-06:00\",\"videoType\":1,\"videoId\":\"Ff8FMTUINa0\",\"type\":5,\"typeId\":62235,\"url\":null},{\"id\":193480,\"user\":\"Mypciscraze\",\"date\":\"2020-12-04T02:53:29-06:00\",\"videoType\":1,\"videoId\":\"6fQOnbHCXZU\",\"type\":5,\"typeId\":62235,\"url\":null,\"caption\":\"Allay Their Fears Bastion World Quest Shadowlands WOW\"},{\"id\":194041,\"user\":\"BloodyBajaz\",\"date\":\"2020-12-08T08:56:05-06:00\",\"videoType\":1,\"videoId\":\"5lVCOQxZrzE\",\"type\":5,\"typeId\":62235,\"url\":null}]; var g_pageInfo = {\"type\":5,\"typeId\":62235,\"name\":\"Allay Their Fears\"}; WH.Layout.set({breadcrumb: [0, 3, 16, 10534]}); //]]> // Links Allay Their Fears &nbsp; Korinna\'s Allaying Crook &nbsp;( 1 ) &nbsp; Allaying Crook charged &nbsp;( 1 ) &nbsp; Wildlife absorbed &nbsp;( 20 ) &nbsp; Coalesced Anima slain &nbsp;( 10 ) &nbsp; Allaying Ritual completed &nbsp;( 1 ) Korinna\'s Allaying Crook &nbsp;( 1 ) WH.ge(\'icon-list-icon1\').appendChild(g_items.createIcon(183045, 0, 1, null, null));', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62258, 0, 0, 'This quest is another example of the exceptional design and quality of Blizzard for this particular expansion. I especially love how the gates many times do not appear after the third one and you get thrown off the larion because you run out of time trying to find gates that never appeared.', 0);
