INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62451, 0, 0, 'HOW TO DO THIS STUPID CONFUSING WORLD QUEST: 1. Talk to Steward Mechanic, and get the core. 2. Charge the core by killing 15-20 enemies in the area. 3. Talk to the Centurion Colossus, . 4. &quot;Mount&quot; the Centurion Colossus, . 5. Press the pet bar button to FIRE THE LASER! 6. Kill Andromede, Herald of the Fosworn .', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62616, 0, 0, 'If you are on this for a while go and check Gormsmith Cavina (/way 51.6 34.0 in Ardenweald). I did Ember Court like 20 times with Hunt-Captin Koryan. Then it turned out I missed it somehow so I was able to just pick up the quest... var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":62616,\"name\":\"Night Fae Arsenal\"}; WH.Layout.set({breadcrumb: [0, 3, 16, -586]}); //]]> // Links Night Fae Arsenal Complete World Quests in Ardenweald. {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
