INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62781, 0, 0, 'This is one I dread doing as it takes so danged long. The light shards do help a lot though. Bonus objectives in this expansion are quadruple the length over every other expansion. I suspect this is due to Threads of Fate being a thing and the extra mob grinding helps with the lack of storyline quests in each zone. But seriously... ooooof.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62784, 0, 0, 'Anybody else wondering why the mobs here are fixed at level 60? I was wondering why I was having trouble killing them, and then I realized they were 6 levels higher than me. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":62784,\"name\":\"Charlatans of Ceremony\"}; WH.Layout.set({breadcrumb: [0, 3, 16, 10413]}); //]]> // Links Charlatans of Ceremony &nbsp; Depravity purged &nbsp;( 1 ) &nbsp; Kill Credit: Cloister (Normal) slain &nbsp;(17) &nbsp; Depraved Tutor &nbsp;( 1 ) &nbsp; Silent Proctor &nbsp;( 1 ) &nbsp; Kill Credit: Cloister (Normal) &nbsp;( 1 ) &nbsp; Depraved Caregiver &nbsp;( 1 ) &nbsp; Depraved Caregiver &nbsp;( 1 ) &nbsp; Depraved Soulflayer &nbsp;( 1 ) &nbsp; Depraved Tutor &nbsp;( 1 ) &nbsp; Depraved Disciple &nbsp;( 1 ) &nbsp; Depraved Disciple &nbsp;( 1 ) &nbsp; Fata the Soulflayer &nbsp;( 1 ) &nbsp; Silent Proctor &nbsp;( 1 ) &nbsp; Depraved Soulflayer &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Kill Credit: Courtyard (Normal) slain &nbsp;(17) &nbsp; Depraved Soulflayer &nbsp;( 1 ) &nbsp; Depraved Witness &nbsp;( 1 ) &nbsp; Kill Credit: Courtyard (Normal) &nbsp;( 1 ) &nbsp; Depraved Soulflayer &nbsp;( 1 ) &nbsp; Depraved Epicure &nbsp;( 1 ) &nbsp; Depraved Stalker &nbsp;( 1 ) &nbsp; Depraved Epicure &nbsp;( 1 ) &nbsp; Depraved Witness &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Kill Credit: Reception (Normal) slain &nbsp;(17) &nbsp; Depraved Interrogator &nbsp;( 1 ) &nbsp; Depraved Notary &nbsp;( 1 ) &nbsp; Carved Intimidator &nbsp;( 1 ) &nbsp; Depraved Soulcollector &nbsp;( 1 ) &nbsp; Kill Credit: Reception (Normal) &nbsp;( 1 ) &nbsp; Depraved Soulcollector &nbsp;( 1 ) &nbsp; Carved Intimidator &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Kill Credit: Archives (Normal) slain &nbsp;(17) &nbsp; Depraved Archivist &nbsp;( 1 ) &nbsp; Depraved Cryptkeeper &nbsp;( 1 ) &nbsp; Depraved Usher &nbsp;( 1 ) &nbsp; Depr