INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62801, 0, 0, 'If you choose &quot;Threads of Fate&quot; does it also lock that particular character out of the achievements tied to the main storyline?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (62866, 0, 0, 'If the quest doesn\'t show up after you change Covenant, relog. I changed covenant when my old Ardenweald was at Renown 80, finished my Necrolord introquest and the \'Return Lost Souls\' quest didn\'t show up, I thought at first maybe I had to just do more of the Necrolord campaign but I was at 4/9 when I decided to relog. The quest finally showed up.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (63594, 0, 0, 'Saturday day 2 of october of 2021. Another Necrolord assault, another one without this quest. Last time it was up? July 12. 3 months, still no quest, still no rare, still no stone ring. Good job with the RNG quests blizz, good job', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (63823, 0, 0, 'The Jailer\'s forces have been caught off guard by our attack. We shall overrun Perdition Hold and defeat his champions at the Altar of Domination! We need your help Maw Walker. Assist our forces on the battlefield!', 0);
