INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (64273, 0, 0, 'If you\'re having difficulty with the elite mobs, you can kill the pack of Chained Dusksavages and Starving Corpsehounds at 67. 60. and 60. 53. A few Helsworn Soulseekers also patrol the are for extra progress. For me killing just those non-elites gave me a 60-70% increase for the progress bar. Hope this helps.', 0);
