INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (66942, 0, 0, 'Azure Span, around 70, 35 where you enter the cavern for the zone questline finale. The Fiery Carvers and other humanoids have a good drop rate, took me like 5 minutes. Stick with the front section of the cave- they are quest mobs and respawn pretty quick. Good Luck!', 0);
