INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70221, 0, 0, 'Hey there &lt;name&gt;! The Artisan\'s Consortium would like to thank you for everything you\'ve done for us. We\'d like to give you some Artisan\'s Mettle free of charge. Maybe use it to fill some recrafting orders for us! {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (7022, 0, 0, 'Have a wondrous Winter Veil, friend! Be sure to say hello to Greatfather Winter ! If you\'ve been nice this year, you\'ll receive wondrous treats on the day of the Feast of Winter Veil. Be sure to tell him what you hope to get this year! Also, be sure to stock up on treats to give those who\'ve been nice this year. We have a great selection to choose from. Fresh from our farm to your plate - it\'s Smokywood Pastures wholesome goodness!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (7023, 0, 0, 'Have a wondrous Winter Veil, friend! Be sure to say hello to Greatfather Winter , who\'s currently in Ironforge! If you\'ve been nice this year, you\'ll receive wondrous treats on the day of the Feast of Winter Veil. Be sure to tell him what you hope to get this year! Also, be sure to stock up on treats to give those who\'ve been nice this year. We have a great selection to choose from. Fresh from our farm to your plate - it\'s Smokywood Pastures wholesome goodness!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70279, 0, 0, 'How goes your hunt?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70439, 0, 0, 'So much for the &quot;We are listening Expansion&quot;, there has been a hunter and druid farming the entire zone for over 2 hours, how is this not gameplay sabotage and zone disruption, they are clearly done, there is no need to be griefing. Edit: They aren\'t even killing players, they are now just one-shotting the mobs without letting anyone get credit and spamming /laugh.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70501, 0, 0, 'Have you completed your training?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70540, 0, 0, '&lt;Clinkyclick is muttering to herself as she looks for something.&gt;', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70617, 0, 0, 'Well? Have you brought me my ore?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70646, 0, 0, 'Small Tip: The elemental mobs required for this quest are also INSIDE the cave within the quest area. Gets quite busy outside, with players often running around trying to find mobs to kill. For some reason people forget to look in the covered cave bit.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70647, 0, 0, 'I hope Lubbins is safe. I am terribly worried.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70654, 0, 0, 'seems to be bugged on 1/1/23. There are 0 handholds near the ground, so you cannot grab them. Oddly enough, I did it on an alt yesterday, and it was fine. :(', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70720, 0, 0, 'The quest was not completable for various reasons. First of all, no one mentioned that mob agro is terrible in this area. They come from everywhere and respawn constantly. Going around looking for the artifacts is suicide unless you are really geared and a lvl 70, and if this is the case you don\'t need to bother with this quest. Bring a friend if you want to do this thing. I was never able to locate all the artifacts and my lvl 69 Warrior got tired of getting killed over and over. The coordinates of 12, 40, 41,42, and 43 indicate that the artifacts appear in a straight line. They don\'t. And some kind of an artifact locator to show you where the artifacts are? Ummm.... Why wasn\'t this item mentioned in the quest? I never heard of it till I came here and will have to research to find out how to get it. This quest is not worth the effort to me, I may come back to it but not any time soon.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70722, 0, 0, 'Let\'s talk!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70789, 0, 0, 'To see this item, you have to talk to Emilia Bellocq first or you won\'t be able to collect them! /way #2022 47.23, 88.48 Finely Carved Wing (coords from Hojzti) Under the dragon\'s right knee and right big toe', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70791, 0, 0, 'To see this item, you have to talk to Emilia Bellocq first or you won\'t be able to collect them! /way #2024 47.83, 38.93 Coldwashed Dragonclaw (coords from Hojzti) Under the water under ice on the lake', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70809, 0, 0, 'You will be able to choose one of these rewards:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70822, 0, 0, 'I completed this quest on a character that is not my main, in fact I did the quest chain up through Digging Up Treasure. This was a big mistake. It unavailable on any of my other characters. The most frustrating thing is I can not interact with Disturbed Earth or Expedition Scout\'s Pack on any character except the one that did the quest chain.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70871, 0, 0, 'Have you found suitable materials? I need strongest vines of kelp, and some good stones with holes in them.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70893, 0, 0, 'Did it for the second time today and got one credit out of 5 for doing the whole event', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70938, 0, 0, 'You need 3 renown with the Iskaara Tuskarr on at least 1 character for any of your characters to be able to participate. It happens every 3 hours patched to be every 1.5 hours and lasts 15 minutes. Check the front page of Wowhead for the timer or get one of the weak auras that tracks it ingame. For example: https://wago.io/RsQlgCLks (Not mine, credits to the author) It takes place at /way 13.6, 48.6 in The Azure Span. It\'s at the giant fish hook icon where the tuskarr hang out, where there\'s a big pot of soup and a tuskarr chef stirring it. How do you know you\'re in the event? It should show up on your objective tracker, looking similar to a scenario or dungeon objective, with a big header and the objective saying to wait for Big Kinook\'s orders. You can receive loot once per week. The loot will scale based on your item level, up to 385. The loot is also NOT specific to your class. I received an agility trinket on my warlock. Edit: There are 2 sources of loot: There is a little tuskarr kid ( Pleeqi ) next to the soup pot that gives the quest Community Feast which rewards a cache, and the final &quot;boss&quot; mob that you kill for the event will also drop loot. Note that Pleeqi \'s quest requires you to do 5 tasks, which you will see one at a time in your objective tracker. It can take a while to get a new task, but remember your quest progress carries over through feasts. Don\'t worry about the people putting down target dummies to try to obscure the \'tenderize morsel\' or \'tough carp\' etc. target. You get credit for that task even without hitting it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70941, 0, 0, 'Are the fish biting?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70954, 0, 0, 'If you\'re super stoked to customize your dragonriding mounts, try to avoid buying any customizations from the vendors until you\'re max renown. I excitedly bought and learned these 3 patterns ASAP, and now my account can never complete this quest since they\'re account-wide rewards. Pretty devastating system for collectors :(', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (70990, 0, 0, 'Take care to avoid the horns. They\'re as sharp as any knife.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (71004, 0, 0, 'Do you have something for the archives?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (71005, 0, 0, 'Do you have something for the archives?', 0);
