INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (71210, 0, 0, 'Seems still bugged. Everywhere people says it starts on every hour. Some say that might start off timed. However I\'ve been waiting here for 55 minutes and event still haven\'t start. I started waiting on 18:45 and NPC spawned around 19:05 and I\'m still waiting the event to activate. Now the time is 19:40.', 0);
