INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72022, 0, 0, 'This WQ is situated in The Azure Span and you need to kill the Icy Blue Crab , which has the nasty sting Slicing Claw if you get in melee range. To avoid getting hit use the harpoon and drag it out of the water and over the ice; but not too close. It will succumb to Drying Out .', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72137, 0, 0, 'My friend, get this thing away from me. Trade for it. Please. They call it a \"Hoofhelper\" but it\'s really just a nuisance. Always getting in the way. Not nearly big enough to be useful yet. I want it gone. What? No, I can\'t just give it to you. My wife would never forgive me. {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} // See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(72137)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(72137))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
