INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72429, 0, 0, 'I look forward to seeing how you contribute to the Maruuk.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72435, 0, 0, 'We have much to offer each other, friend.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72448, 0, 0, 'Hi all On This Quest You need to Slay two rare enemies within the Obsidian Citadel or Slagmire. I Slay Turboris 33.01 55.61 and Battlehorn Pyrhus 28.50 59.33 but you have 9 rare in this area which you can kill to finish this quest. See My Video if need it - https://youtu.be/7APErusjpTQ See My Video with all location of NPC, Rares, shops ect. - https://youtu.be/RclLJYzxn-8 See My Video for 2x4 farm party if need it - https://youtu.be/peR4489d-o4 How to do 2x4 party in spoiler: First go on spot wher you want to do 2x4 farm. Spots: 24.6 58.1 In Basement 28.3 58.8 25 56 in Basement Then Create party in LRG call &quot;2x4 Key Basement WMoff gr1&quot; When You get to 5 please give someone who know that He need to keep max 4 please in party. Then open new party call it &quot;2x4 Key Basement WMoff gr2&quot; No just keep 4 people in 2 party Mobs will start spawn much faster and farm will go faster to. . Is nice Quest for Wrathion reputation - 2500 :D You need to do it :). Hope That help You :)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72456, 0, 0, 'Have you found the tomes?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72481, 0, 0, 'For anyone else that cannot interact with the Bronze Timekeeper, if you signed up for the race it will prevent you from starting the tour. I was unable to start until I dropped out of the race or completed it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72528, 0, 0, 'World boss gives 50% Do this on 2 characters, and you\'re finished. That\'s it. Ignore all that other crap about 10% here or there, just do the world boss on 2 characters, and you\'re done Edit- Annnnd they nerfed this already, because of course they did. It gives about 20 percent now. Gg', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72551, 0, 0, 'First marker is roughly /way 62.04, 18.43 Second marker is /way 57.36, 20.08 Last marker is /way 57.4, 21.0 Elder Mhaz', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72584, 0, 0, 'Don\'t forget, south of Waking Shores. Go.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72728, 0, 0, 'You know you\'re tough when you\'re helping out your community.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (72972, 0, 0, 'I\'ve made a guide on how to get gold medals for the achievement on all of these reverse races. I also made a custom WeakAura that shows more clearly what ability I\'m using when, so you know when to use Surge Forward and when to use Skyward Ascent. The video description has timestamp links to the individual races. Walking Shore Reverse Tour YouTube Guide Here are links to the videos for the other Reverse Tour challenges in the other three zones: Thaldraszus Reverse Tour YouTube Guide Azure Span Reverse Tour YouTube Guide Ohn\'ahran Plains Reverse Tour YouTube Guide I really enjoy these races and I hope the videos help someone!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (73191, 0, 0, 'You will receive: Elemental Overflow WH.ge(\'icontab-icon1\').appendChild(g_gatheredcurrencies.createIcon(2118, 1, \"450\"));', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (73227, 0, 0, 'Daughter of Malygos and Saragosa, Kirygosa survived the turbulent Nexus War that ripped away her life and family. Afterwards, Kirygosa sought a permanent summer in Stranglethorn. Finding warmth but not quite peace, she moved on to Dawn\'s Blossom, a small village nestled in the Jade Forest. The blue dragonflight would welcome her return.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (73408, 0, 0, 'The scent trail moves apparently, I did this quest two days ago the same way on multiple alts, through the cave. Then today, I looked in the same spot, the trail was NOT there at all. I ran through the whole cave pretty much, no trail. I went outside about to give up thinking it is bugged and i saw the green scent trail just outside the cave (fully outside the cave, the whole trail and 5 digs) this time. So moral of the story is, if you can\'t find it and you did it on alts a few days ago, well look around it\'s moved.', 0);
