INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75200, 0, 0, 'Be aware that there are valid mobs located outside of the valid world quest area. If you leave the designated area to kill them, it will not count.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75222, 0, 0, 'It is too slow-moving when you are alone. Doable with one or more additional players. You fight the flames, the embers, and the snail running you over. In addition, you have to grab the water buckets and throw them on the burning snail which takes time while the snail can make sudden 180-degree moves.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75232, 0, 0, 'If you have completed everything within the campaign and the body is still not showing up for you like it was for me, Head to the Dragonscale Base Camp and pick up one of the npc quests like Healing Crystals or Medicinal Fungi and head back over to the body and it should be visible. For whatever reason having one of these quests in my log was what finally prompted me to see the npc.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75280, 0, 0, 'You will receive: Iskaara Tuskarr Insignia WH.ge(\'icontab-icon1\').appendChild(g_items.createIcon(200453, 1, \"1\")); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(75280)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(75280))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75345, 0, 0, 'Oh, I get it now! Quest is called Shell Corporation - like that awful company - it\'s supposed to suck as hard as possible...', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75455, 0, 0, 'Rather than continuously channeling, try out clicking the orb as many times as possible. Edit: The channeling time is somewhat faster than at the time of writing.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75461, 0, 0, 'Kill the magma claw supplicants and throw their food into the lava. A bar appears over the fire whirlpool in the middle of the lava lake showing the progress of the ritual disruption. var lv_screenshots = [{\"id\":1233180,\"user\":\"Rantsi\",\"date\":\"2025-08-04T02:09:02-05:00\",\"width\":1600,\"height\":900,\"type\":5,\"typeId\":75461,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":75461,\"name\":\"Magmaclaw Matriarch\"}; WH.Layout.set({breadcrumb: [0, 3, 17, 14022]}); //]]> // Links Magmaclaw Matriarch &nbsp; Magmaclaw Ritual Disrupted &nbsp;( 1 ) &nbsp; Kill Credit: Magmaclaw Matriarch Participation slain &nbsp;(1) &nbsp; Magmaclaw Supplicant &nbsp;( 1 ) &nbsp; Magmaclaw Queen &nbsp;( 1 ) &nbsp; Kill Credit: Magmaclaw Matriarch Participation &nbsp;( 1 ) &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75471, 0, 0, 'Drop rate isn\'t so bad, just kill adds in the area. Agitated Crystalline get you about 4% with each kill. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":75471,\"name\":\"Crystalline Survey\"}; WH.Layout.set({breadcrumb: [0, 3, 17, 14022]}); //]]> // Links Crystalline Survey &nbsp; Mordigan Ironjaw\'s survey completed &nbsp;( 1 ) &nbsp; Agitated Crystalline slain &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75478, 0, 0, 'Annoying how blizzard named this objective almost exactly the same as the one from BFA. That can be VERY confusing to some folks.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75611, 0, 0, 'Seems bugged (at least for some servers.) The objective pops up on your screen when in the vicinity of the river, but going up and down it shows no giant glimmerfish.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (75860, 0, 0, 'You complete the Kill Credit: Researchers Under Fire part when defeating Captain Reykal . It is not required to get 12/12 within 25 minutes. It\'s just the higher you get, the better the reward will be. The event starts every hour at x:30. It\'s not clear to me what the minimum requirements are to spawn Captain Reykal during &quot;Leader to a Flame&quot;.', 0);
