INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (76506, 0, 0, 'Still bugged on EU servers as of 10th november, 14:21 CET. A random person could complete it but he had not done the campaign quests. I have done the available campaign quests but have yet to do the other quests that shows up after, will update this post after I have and see if it makes any difference. Update! Party-syncinc with people that havent started the campaign makes you able to complete this quest! There are already a bunch of groups starting up in LFG-tool but are buggy if people are in combat. Best bet to find a friends alt and sync up with them. :)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (76520, 0, 0, 'The spawn rate is so bad it feels like a classic quest It\'s fixed', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (76586, 0, 0, 'Odd sort of glitch that\'s been happening to me the past few days, though it hasn\'t affected the actual completion of the quest. When lighting a keyflame, the first radiant remnant I put in isn\'t tracked. Then I put the second one in and it jumps to two. Again, doesn\'t affect functionality, just odd.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (76587, 0, 0, 'I was a little confused on how to actually do this world quest as no indicators popped up on my mini map telling me where to go. Once you have the little frog following you around, mount up and search the area for the following: -Green spirit frogs to click on called &quot;Juicy Clue&quot; -Blue pillars of light with some level 1 mini frogs hopping around it. Get close to the pillar of light and an extra action button will show up. Click the &quot;Gain Clue&quot; action button and your spirit frog companion will consume the mini frogs. With each of these activities your progress bar will fill up and the WQ should complete.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (76588, 0, 0, 'Have you eliminated the threats?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (76991, 0, 0, 'Found and achieved the fish. THOUGHT I got the first waterfall. Got all the other waterfalls and discovered that the first one would NOT work.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (76997, 0, 0, 'Have you found the recruits?', 0);
