INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (77570, 0, 0, 'This comes up as a &quot;regular&quot; quest, but is absolutely not - it\'s minimum 5 person group or small raid quest. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":77570,\"name\":\"Nuoberon, the Wild Dream of a Child\"}; WH.Layout.set({breadcrumb: [0, 3, 17, 14529]}); //]]> // Links Nuoberon, the Wild Dream of a Child &nbsp; Participate in Nuo\'s dream to summon a massive creature &nbsp;( 1 ) &nbsp; Nuoberon slain &nbsp;( 1 ) &nbsp; Suggested players: 5 &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (77714, 0, 0, 'I attacked a big stone thing, didn\'t look special. But spawned flame elementals, had stuns and basically kicked my butt. I had a few points. But don\'t like the hidden aspect. Not going back.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (77815, 0, 0, 'I had trouble with Vakthros Ascent (Azure Span race) but soon realised I was focusing on using Lightning Rush on CD/ASAP (cos it\'s FUN! :D ) which just wasn\'t working for this race. I was able to get race time of 116 secs, down from a consistent ~125sec. Use Lightning Rush in the first long straight section near the beginning of the race (you should fairly easily be able to get the 10 stacks required by the time you reach the turn heading into the first big straight) . Surge occasionally on the next downward section and maintain momentum around the turns at the bottom . Build up some vigor in the downward section near the towers/bridge, and focus on using surge forward while maintaining 10 stacks ready to use Lightning Rush when you hit the straight section across the frozen lake at the top of the ascent. After that surge forward to the end! Good luck!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (77838, 0, 0, 'Genuine question: Can a character only complete the companion quest once to help someone with the restored dreamleaf? It seems counter productive to have a one time limit per character to help people out.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (77976, 0, 0, 'A group of druids from across Azeroth have gathered to investigate a sudden surge in energies coming from the Emerald Dream. This has the potential to affect us all, &lt;name&gt;. Please aid them in their endeavor to understand this new phenomena.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (78203, 0, 0, 'If we can control the *!@#$%^&amp;*!@#, a smarter way to fight the last fight in these is not to bunch up at each entrance point, but to kite the mobs to a central point and fight there. This allows everyone\'s non-target capped AOE* to have more impact. * For instance, A warrior\'s Whirlwind can hit a lot of mobs at once, and while it does less impact beyond 5 mobs, it still hits the others.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (78370, 0, 0, 'Up today in EU', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (78616, 0, 0, 'My second object was near impossible to find. The closest I got was 97% It turned out to be a circle fitter located mid-air at 57.8:44.4.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (78657, 0, 0, 'It is the large keyflame (Torchlight Mine Keyflame) at /way 63.96 19.68 The quest itself involves throwing flares from an item you get after activating the keyflame ( Sentry Flare ). You get the quest immediately after activating the large keyflame, no need to pick it up. Throw the flares along the rocks surrounding the keyflame, you should be able to get the Shadowed Gloomrender s to show. Beware they are an elite mob, but unless you are on a fresh level 80 character, it should be very easy. Part of Sharing the Light achievement, but if you stumbled upon this page, you are probably looking on how to complete it. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":78657,\"name\":\"The Midnight Sentry\"}; WH.Layout.set({breadcrumb: [0, 3, 18, 14838]}); //]]> // Links The Midnight Sentry &nbsp; Shadowed Gloomrender slain &nbsp;(10) &nbsp; Shadowed Gloomrender &nbsp;( 1 ) &nbsp; Shadowed Gloomrender &nbsp;( 1 ) &nbsp;( 1 ) &nbsp; Enemy revealed using Sentry Flare &nbsp;( 1 )', 0);
