INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (78877, 0, 0, 'You do us an honor, bringing your faith into these caverns. Let it bless these machines and those who work with them, just as they bless us in turn.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (79960, 0, 0, 'i\'d be tempted to say this is the worst world quest of the expansion but competition is tough they just need to stop making things annoying and remember we\'re supposed to have fun', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (80573, 0, 0, 'War chest location: Sureki War Chest', 0);
