INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (81630, 0, 0, 'If you kill him in raid, the WQ does NOT count to The World Awaits , but counts to Worldsoul: Encore! . var lv_screenshots = [{\"id\":1197909,\"user\":\"Rantsi\",\"date\":\"2024-10-30T14:58:05-05:00\",\"width\":1600,\"height\":900,\"type\":5,\"typeId\":81630,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":341639,\"user\":\"gtulgar1903\",\"date\":\"2024-10-02T02:00:48-05:00\",\"videoType\":1,\"videoId\":\"PGwHYa8_43w\",\"type\":5,\"typeId\":81630,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":81630,\"name\":\"Activation Protocol\"}; WH.Layout.set({breadcrumb: [0, 3, 18, 14717]}); //]]> // Links Activation Protocol &nbsp; Kordac slain &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} // See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(81630)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(81630))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (81675, 0, 0, 'The Parched Mosswool is about a 3 second cast - you can punt the pest (Stone Borer) at the same time as you\'re casting the Mosswool, to help speed this along!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (81710, 0, 0, 'Legendary shoot is a blue bird flying around 80, 40 called Shraubendre var lv_screenshots = []; var lv_videos = [{\"id\":342723,\"user\":\"gtulgar1903\",\"date\":\"2024-10-11T23:08:47-05:00\",\"videoType\":1,\"videoId\":\"Z2AnrsqAiag\",\"type\":5,\"typeId\":81710,\"url\":null,\"sticky\":1},{\"id\":344592,\"user\":\"Monatoet\",\"date\":\"2024-10-28T06:40:15-05:00\",\"videoType\":1,\"videoId\":\"3xhbHw8W-AY\",\"type\":5,\"typeId\":81710,\"url\":null}]; var g_pageInfo = {\"type\":5,\"typeId\":81710,\"name\":\"Mead for the Catalog\"}; WH.Layout.set({breadcrumb: [0, 3, 18, 14717]}); //]]> // Links Mead for the Catalog &nbsp; Ride the Cataloger\'s Disc &nbsp;( 1 ) &nbsp; Take Pictures of Wildlife &nbsp;( 1 ) &nbsp; Common &nbsp;( 34 ) &nbsp; Rare &nbsp;( 20 ) &nbsp; Epic &nbsp;( 10 ) &nbsp; Legendary &nbsp;( 5 )', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82088, 0, 0, 'Does anyone know why the green guys are highlighted, but there\'s no interaction, no tool or extra button to interact. It also doesn\'t matter if you attack ads near them, they just stand there. var lv_screenshots = []; var lv_videos = []; var g_pageInfo = {\"type\":5,\"typeId\":82088,\"name\":\"Kobyss Kibosh\"}; WH.Layout.set({breadcrumb: [0, 3, 18, 14838]}); //]]> // Links Kobyss Kibosh &nbsp; Assist the Arathi in driving back the kobyss &nbsp;( 1 ) &nbsp; [DNT] Kill Credit: Heal Arathi Stalwart slain &nbsp;( 15 ) &nbsp; Kobyss Attackers slain &nbsp;(15) &nbsp; Ragefin Carver &nbsp;( 1 ) &nbsp; Ragefin Shadowcaster &nbsp;( 1 ) &nbsp; Ragefin Executioner &nbsp;( 1 ) &nbsp; Kobyss Attackers &nbsp;( 1 ) &nbsp; Grimslice &nbsp;( 1 ) &nbsp; Order of Night Adept &nbsp;( 1 ) &nbsp; Ragefin Necromancer &nbsp;( 1 ) &nbsp; Ragefin Carver &nbsp;( 1 ) &nbsp; Darkwater Tidecrusher &nbsp;( 1 ) &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82155, 0, 0, 'Don\'t forget to check your bags for Radiant Fuel Shards. This went faster when I realized I had a bunch of these in my bags and combined them to create the Radiant Fuel Crystal you need to use.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82288, 0, 0, 'For &quot;Floor is Undersea - Challenge&quot; I used my warrior and did almost the non challenge route by using &quot;heroic leap&quot; to easily jump across the first, large fence gab. sadly you cant jump with heroic leap to the last floor piece - this quite easy part of the challenge you have to play.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82324, 0, 0, 'I watch for this Quest FROM 28 Noember EVERY SINGLE DAY and still not spawn ! i also will made report bug ... please everyone make the same - write a bug report for this quest issue !', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82332, 0, 0, 'You can still fly while carrying the items, so its easier easy just to mount up and dash into the delivery room, no need to stay on the ground and run. The big chests give way more percentage, so find 3 large chests and fly them back.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82363, 0, 0, 'The carpet will take you down a long road that turns right, and then after a long journey down that road, you\'ll reach the crashed webbed airship that started the Azj-Kahet campaign and some camps. Fahl\'khax is the easily spotted hostile mob standing with some other neutrals at the first camp as your carpet starts to bank to the right again towards the zone exit.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82414, 0, 0, 'As of 11/Sep/2024, the quest is bugged -at least partially: You can find and kill the boss in the cave, but all other mobs are not present at all, due to a bug with phasing. Thus leading you getting stuck at 75% completion and no way to hit 100%.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82468, 0, 0, 'Another one of these stupid quests where its not clear at all what to do.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82519, 0, 0, 'Today, I flew into the designated area, did some killings and picked up some packages until I reached 12. Stuck there without completion. Then I just flew out of the area and back and it completed the quest with submitting the reward', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82521, 0, 0, 'You have to get 50 stacks of the debuff by clicking the things BUT make sure you don\'t click the lighter colored item it will clear your stacks :( Once you have over 50 stacks you will start seeing the Elite mobs. Kill 1-2 of these and quest done!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82552, 0, 0, 'There used to be friendly NPCs to talk to and they would either evacuate or turn hostile and attack you. Now there is no dialogue option on the friendly NPCs There are also Broken Machinery objects that spout fireballs you have to dodge until cast bar finishes to destroy, these used to give 12% on the completion bar but however no longer offer any progress. I believe this is just a bug from where the campaign quest mechanics didn\'t get carried over to the World Quest, so yes you will need to kill hostile NPCs each NPC is 2% - 4% on the progress bar', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82582, 0, 0, 'Progress shows on the world map - mouse over the world quest icon. It appears no progress on the mini-map, but there is progress.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82615, 0, 0, '&quot;Brutes&quot; are just extra large kobalds. There may not be many of them. Found some on the level with the gem thieves. (Note: they are NOT the kelp mobs).', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (82653, 0, 0, '// new Listview({ data: lv_comments0, id: \'comments\', name: WH.TERMS.comments, parent: lkljbjkb574, tabOpts: {className: \'ugc-tab ugc-tab-comments\'}, tabs: tabsRelated, template: \'comment\', });new Listview({ data: lv_screenshots, id: \'screenshots\', name: WH.TERMS.screenshots, parent: \'lkljbjkb574\', tabOpts: {className: \'ugc-tab ugc-tab-screenshots\'}, tabs: tabsRelated, template: \'screenshot\', });if (lv_videos.length) { new Listview({ data: lv_videos, id: \'videos\', name: WH.TERMS.videos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); } if (window.lv_videos_english && lv_videos_english.length) { new Listview({ data: lv_videos_english, id: \'videos-english\', name: WH.TERMS.englishvideos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); }tabsRelated.flush(); //]]>', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (8295, 0, 0, 'You will receive:', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (83079, 0, 0, 'This WQ takes age to complete, one of the worst WQ so far in TWW.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (83496, 0, 0, 'Did you find the bank?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (83537, 0, 0, 'Terrible quest; you have to fight mobs to get the quest items and them fight mobs to turn in the quest items.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (84254, 0, 0, 'It\'s easy to get distracted. Have you spoken with the activity greeters I told you about?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (84489, 0, 0, 'Don\'t be shy, you\'re allowed to browse. Go ahead and have a look at the wares for sale and then come back when you\'re done.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (84616, 0, 0, 'I think something changed between now and earlier comments. I\'ve logged in and done this quest 2 days in a row and both days have given me tokens, so maybe this isn\'t a weekly reward but daily now?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (84619, 0, 0, 'Did you find anything worth reading?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (84779, 0, 0, 'Another batch of recycled bug-ridden quests that nobody asked for. Lorewalking: Blade\'s Bane Echo of Xal\'atath, Blade of the Black Empire Lorewalking: Ethereal Wisdom K\'aresh Memory Crystal Lorewalking: The Lich King Royal Visage On the brighter side, the toys actually do look pretty cool.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (84782, 0, 0, 'Another batch of recycled bug-ridden quests that nobody asked for. Lorewalking: Blade\'s Bane Echo of Xal\'atath, Blade of the Black Empire Lorewalking: Ethereal Wisdom K\'aresh Memory Crystal Lorewalking: The Lich King Royal Visage On the brighter side, the toys actually do look pretty cool. var lv_screenshots = [{\"id\":1230554,\"user\":\"auryunderground\",\"date\":\"2025-07-11T05:51:53-05:00\",\"width\":1600,\"height\":900,\"type\":5,\"typeId\":84782,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":376873,\"user\":\"gtulgar1903\",\"date\":\"2025-06-22T19:57:49-05:00\",\"videoType\":1,\"videoId\":\"hP_S64fKuuc\",\"type\":5,\"typeId\":84782,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":84782,\"name\":\"Lorewalking: The Blade\'s Past\"}; WH.Layout.set({breadcrumb: [0, 3, 19, -647]}); //]]> // Links Lorewalking: The Blade\'s Past Listen to Cho to learn the story of Xal\'alath in Ny\'alotha. &nbsp; Listen to Lorewalker Cho to learn of Xal\'atath\'s distant past &nbsp;( 1 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (85268, 0, 0, 'So we have to fight our way through mobs of Darkfuse to get to this effing WQ to begin with... UGH. For anyone like me who can\'t find the cannon, you have to go into the walled off area with the Darkfuse and the cannon is on the dock at the back right of the area. And just running to the cannon doesn\'t throw them off, they will follow you into the water and continue attacking. EDIT: The quickest way to the cannon is out the back door of the Port Authority, where the Blackwater Cartel quartermaster is. Go through the archway on her left, then go out the door on the right the big oaf is guarding, but be aware you will be mobbed by Darkfuse.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (85390, 0, 0, 'I have a feeling this quest/world quest is a reference to Super Mario Sunshine.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (85460, 0, 0, 'Upon completion of this quest you will gain: WH.Wow.Quest.setupScalingRewards({\"minLevel\":70,\"maxLevel\":70,\"xp\":{\"multiplier\":1,\"levels\":{\"70\":9515}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":1,\"levels\":{\"70\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(85460)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(85460))\");', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (85487, 0, 0, 'As of 12.0, this quest seems to be MUCH more forgiving on those coveted upper body &quot;head&quot; shots. I had no interest in a fix making this quest work as one might logically expect when the content waas relevant. Of course, I would much prefer the fix to come now. TY Blizzard &lt;3', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (85771, 0, 0, 'Yeah this seems to be broken. Did all the reload, relogs and rezones and nothing. Just a circle on mini map and green arrow pointing here. Can\'t even go on to the next because it won\'t update.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (85863, 0, 0, 'A Phase Conduit is East of the Quest spot. At coordinates 77,48', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (86367, 0, 0, 'go to 69.56, 55.92 usually has like 5 of them around there, no mobs attack need', 0);
