INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (86414, 0, 0, '// new Listview({ data: lv_comments0, id: \'comments\', name: WH.TERMS.comments, parent: lkljbjkb574, tabOpts: {className: \'ugc-tab ugc-tab-comments\'}, tabs: tabsRelated, template: \'comment\', });new Listview({ data: lv_screenshots, id: \'screenshots\', name: WH.TERMS.screenshots, parent: \'lkljbjkb574\', tabOpts: {className: \'ugc-tab ugc-tab-screenshots\'}, tabs: tabsRelated, template: \'screenshot\', });if (lv_videos.length) { new Listview({ data: lv_videos, id: \'videos\', name: WH.TERMS.videos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); } if (window.lv_videos_english && lv_videos_english.length) { new Listview({ data: lv_videos_english, id: \'videos-english\', name: WH.TERMS.englishvideos, parent: \'lkljbjkb574\', tabs: tabsRelated, tabOpts: {className: \'ugc-tab ugc-tab-videos\'}, template: \'video\', }); }tabsRelated.flush(); //]]>', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (86428, 0, 0, 'This event is not bugged. If you talk to the NPC Boatwright Frankle, he explains what you need to do and, in red text below, it says: (Requires Undermine Renown 6 and Blackwater Cartel weekly contract.) If you have chosen another cartel for your weekly progress, you will NOT be able to turn these in even though you can collect them if the event is active . If other people who are working for Blackwater that week summon the rare, you can kill it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (86610, 0, 0, 'for me just flying to all the mail spots while doing other stuff worked, so you dont HAVE to phase dive to deliver the mail. I think it\'s just somewhat bugged in general and &quot;doesnt always work&quot;', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (86696, 0, 0, 'Upon completion of this quest you will gain: WH.Wow.Quest.setupScalingRewards({\"minLevel\":80,\"maxLevel\":80,\"xp\":{\"multiplier\":1,\"levels\":{\"80\":11765}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":1,\"levels\":{\"80\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(86696)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(86696))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (86707, 0, 0, 'Upon completion of this quest you will gain: WH.Wow.Quest.setupScalingRewards({\"minLevel\":80,\"maxLevel\":80,\"xp\":{\"multiplier\":1,\"levels\":{\"80\":11765}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":1,\"levels\":{\"80\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(86707)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(86707))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (86938, 0, 0, 'i can confirm the quest is still bugged. the quest will despawn and you can not hit the orbs. i have reload a thousand times and its still not working.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (86952, 0, 0, 'Ikky (1, 1, 1) Zandalari Anklerender (2, 2, 2) Any third (I didn\'t need to use it) Use black claw and flock on each pet. Use Primal cry on Anklerender if the second enemy is about to die.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (87477, 0, 0, 'The nerubians have brought every foul, multi-limbed horror from the depths in this swarm! We cannot allow our holdings to fall!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (87480, 0, 0, 'We will hold this position. Go, help Dunelle\'s Kindness below!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (87588, 0, 0, 'If there is a world quest active nearby this quest wont let you interact. Go do the nearest world quest, come back and jump up and down on top of the bin (not in the car) and the quest should then complete.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (8868, 0, 0, 'Omen yet stirs below below Lake Elune\'ara, &lt;name&gt;...', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (88916, 0, 0, 'Doesn\'t appear to be any option to collect the light to burst the eggs', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (89063, 0, 0, '&lt;After defeating the devourer invasion, you pulled this solid lump of anima from their leader\'s stomach. Ve\'nari may find this useful for powering the eco-domes.&gt;', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (89294, 0, 0, 'This quest was bugged for me. I was able to find Kal\'shin, but after talking to him I was immobilized. I could not walk, or turn. I could mount and use some abilities. I tried reloading, but the only thing that worked for me was exiting the game.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (89404, 0, 0, 'Khadgar needs your help.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (89405, 0, 0, 'Dalaran could use a few less demons.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (89418, 0, 0, 'This quest seems to be bugged if you take the portal back instead of talking to the NPC and flying. I was able to use my hearth to go back to the island. I had set my hearth there when doing the quests. Not sure if there is another way back.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90838, 0, 0, 'You, stranger... do you know of the Shadowguard that left K\'aresh in ruins? My sister was lost in the conflict, her heart forcibly turned to the Void, but I swore oaths to my family... to cherish them no matter their transgressions. My sister, Veraan, is surely lost, but if I were to recover her necklace, at least then my oaths would be upheld in spirit. I am a simple tinkerer. I\'ve tuned this device to track the Shadowguard, but I cannot face them alone. Would you help me?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90879, 0, 0, 'Get cookin\'!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90885, 0, 0, 'Return to Thrall with Farmer Bruvk and his pumpkins', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90886, 0, 0, 'Did you recover the plans? They should be on most of the foes within the farm.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90887, 0, 0, 'We\'ll stay here and guard the remaining farmers while you handle Runk .', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90896, 0, 0, 'Defeat Ro\'grok and end this siege.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90938, 0, 0, 'Fleshling, do you know about Untethered Space? I am sure you know someone who has encountered it. Previously we assumed that only beings of energy such as those from K\'aresh could Phase Dive. Since the Harbinger\'s return, she has created a means for solid creatures to become energy using Reshii Wraps . My name is Hashim , and I have some Reshii Wraps in my possession. We are in desperate need of adventurers powerful enough to brave the lucrative depths of Untethered Space.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90962, 0, 0, 'May be bugged on live. Has been at Wave 1 - 00:00 for about an hour now', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90968, 0, 0, 'I finished lorewalking mode and im out of it and the quest doesnt appear on dungeon journal. I have no idea what is happening. Do you guys have any idea?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (90969, 0, 0, 'Adventurer, the rumors are true. I\'ve seen the titan forces and they are nae friendly. We must try tae discover why they are emergin\' now and try and stop \'em from doin\' too much damage. Confront and stop these renegade constructs. To help ye, I\'ve procured some Titan Consoles. I was able to set them up in the affected areas. I can use them to communicate with ye in the field. I am thinkin\' we can use them to counter these titan forces as well.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91096, 0, 0, 'You complete this by doing world quests, chests, rares etc in the zone you picked (red crystal on the map). While you\'re at it the boss will spawn on you from time to time and then disappears until you done enough and can kill it. var lv_screenshots = []; var lv_videos = [{\"id\":408637,\"user\":\"Peteplayed\",\"date\":\"2026-03-03T14:08:02-06:00\",\"videoType\":1,\"videoId\":\"zoehEczVmHc\",\"type\":5,\"typeId\":91096,\"url\":null,\"caption\":\"The COMPLETE Level 90 Gearing Guide (Midnight Pre-Season)\",\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":91096,\"name\":\"Prey: Magistrix Emberlash (Normal)\"}; WH.Layout.set({breadcrumb: [0, 3, 19, -656]}); //]]> // Links Prey: Magistrix Emberlash (Normal) Hunt down Magistrix Emberlash and slay her. Hunt Progress is made by completing Prey activities, World Quests, rares, and treasures in your selected zone. &nbsp; Hunt your Prey &nbsp;( 1 ) &nbsp; Magistrix Emberlash slain &nbsp;( 1 )', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91098, 0, 0, 'Tooltip says it\'s in Voidstorm, flown all over and nothing. Then I decided a google search was in order and found this: https://www.youtube.com/watch?v=7VPEIAylMp8 SO it will appear on the map. There is no icon on my map for this Zone.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91099, 0, 0, 'The Void is a perfidious thing, like water. The wise keep it at a respectful distance, never dancing too close to the edge. The foolish dive in, and in so doing, drown. Mordril is a danger to himself and everyone around him, so lost is he in his own obsession. See to it that he no longer poses a threat to this realm.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91104, 0, 0, 'Our neighbors produce some of the most skilled hunters in all of Azeroth. It is a shame they are so difficult to reason with. There is one named Zadu. Her anguish would make for a most excellent trophy...', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91117, 0, 0, 'Death knights are unstable killing machines at the best of times. Knight-Errant Bloodshatter has forsaken any oath or promise that would ostensibly bind one of his kind to the bottom rungs of civilized society, and has gone completely rogue. He is starting to become a liability. Recoup his anguish so that we can make the best of such an unfortunate situation.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91123, 0, 0, 'The Twilight\'s Blade are an embarrassing band of mediocre cultists and uninspired conspirators. Grothoz is the brains of a particularly stupid cabal that has been active in a nearby region. As his stupidity prevents him from using his whole brain, let us unlock his potential for him...', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91138, 0, 0, 'This is part of the Priest-exclusive short questline The Legacy of T\'uure , which begins from A Curious Crystalline Fragment . The item is dropped by Dimensius on any difficulty (even in Storymode) in Manaforge Omega . ------------------------------------------------------------------------------------------------------------------ Not exactly sure if it matters what you kill for the &quot; Worthy Creatures Destroyed &quot; part , but I was all over TWW zones killing things at least, and the 20 enemies got fairly fast done. //As stated by astleyt07 , the enemies need to be same level as you . ------------------------------------------------------------------------------------------------------------------ Players Resurrected part took me 12 times (each one giving 9% towards the bar) to cast Resurrection on fallen player. This took me about less than 5 minutes to do. Not sure if intended , but the way I did it: If you have another account (even trial is fine) to have another character or a friend to help: have their character die and stay in their corpse - DO NOT CLICK RELEASE! Each time you cast Resurrection on the fallen player character you get credit towards the bar - as long as there isn\'t already pending resurrection attempt. Have the other character/player decline each resurrection , which will remove the &quot;pending resurrection&quot; - DO NOT ACCEPT IT! Then cast Resurrection again on them after the other character/player has declined it. Do this 12 times, and you should be done. ------------------------------------------------------------------------------------------------------------------ Mass Resurrection gives you credit only for one resurrection , so be aware that trying to use it to get all done in one go won\'t work. (Currently at least as of writing this post)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91173, 0, 0, 'Ready yourself soldier, the battle is still to come.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (9120, 0, 0, 'BLESSED LIGHT! What foulness do you hold, $g?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91252, 0, 0, 'This one presents a prickly problem indeed. Thornspeaker Edgath has made a name for himself by using his druidic powers not to preserve Azeroth, but to twist its strength both against his enemies and innocent bystanders alike. He has no regard for anything that is not a beast or growing in the ground. It is time we clip this thorn.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91259, 0, 0, 'I have heard that there is one under Xal\'atath\'s command who takes particular delight in dominating their foes. Whispers of a domanaar that taunts its victims with whispers and riddles before annihilating their mortal coil with void magic. Consul Nebulor is their name. Go and show them the limits of their power.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91483, 0, 0, 'There are consoles inside the Manaforge that keep the flow of energy running smoothly within the facility. We\'ve cracked security on the first set of them, allowing you to turn the tables on enemies near Loom\'ithar and Soulbinder Naazindrhi. You\'ll only be able to use one, but sabotaging them should allow you an edge in battle. Good luck in there.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91484, 0, 0, 'We found a weakness in Forgeweaver Araz\'s engineering bay that should allow you access to another console nearby. Keep up the pressure, and we\'ll let you know once the whole facility is ours. Happy hunting.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91487, 0, 0, 'You will receive: Vandal\'s Gearglider WH.ge(\'icontab-icon1\').appendChild(g_items.createIcon(186640, 1, \"1\")); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(91487)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(91487))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91525, 0, 0, 'Have you procured a sample?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91526, 0, 0, 'Does the Forgeweaver yet live?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91695, 0, 0, 'We must turn our attention to Fyrakk and Vyranoth with Iridikron seemingly vanished from our sight. Merithra and the Green Dragonflight have been pursuing him and have a lead. They\'ve received the aid of Shandris Feathermoon in this task. She awaits you within Valdrakken. Shandris will need your help with what is to come.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91759, 0, 0, 'Both the dispel of the Voidcrawlers and killing Twilight Blade forces doesn\'t count towards completion on my DH, world quest appears to be bugged. var lv_screenshots = [{\"id\":1272402,\"user\":\"auryunderground\",\"date\":\"2026-02-23T14:19:07-06:00\",\"width\":1600,\"height\":900,\"type\":5,\"typeId\":91759,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":399488,\"user\":\"gtulgar1903\",\"date\":\"2026-01-30T00:00:03-06:00\",\"videoType\":1,\"videoId\":\"LLjDnpiPWqk\",\"type\":5,\"typeId\":91759,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":91759,\"name\":\"Don\'t Bring That Here\"}; WH.Layout.set({breadcrumb: [0, 3, 0, 4922]}); //]]> // Links Don\'t Bring That Here &nbsp; Imminent Voidcrawlers dispelled &nbsp;( 4 ) &nbsp; Twilight\'s Blade forces slain &nbsp;( 8 ) {\"ox\":\"This quest has objectives in $$.\",\"sx\":\"This quest starts in $$.\",\"ex\":\"This quest ends in $$.\",\"sex\":\"This quest starts and ends in $$.\",\"osx\":\"This quest has objectives and starts in $$.\",\"oex\":\"This quest has objectives and ends in $$.\",\"osx_ey\":\"This quest has objectives and starts in $$ and ends in $$.\",\"oex_sy\":\"This quest has objectives and ends in $$ and starts in $$.\",\"sx_ey\":\"This quest starts in $$ and ends in $$.\",\"ox_sy\":\"This quest starts in $$ and has objectives in $$.\",\"ox_ey\":\"This quest has objectives in $$ and ends in $$.\",\"ox_sey\":\"This quest starts and ends in $$ and has objectives in $$.\",\"ox_sy_ez\":\"This quest starts in $$, has objectives in $$ and ends in $$.\"} //', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91863, 0, 0, 'Have you found your forever home?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (91968, 0, 0, 'In case you\'re an idiot like me, the tutorial shows you on the right side of the screen that selecting an already placed item and pressing &quot;R&quot; will remove it.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (92608, 0, 0, 'I enjoy roaming around the neighbourhood, even did all the Lost Architect quests without help, but relatively speaking this is quite a bit of work for a mere three coupons and no house XP. var lv_screenshots = []; var lv_videos = [{\"id\":408689,\"user\":\"gtulgar1903\",\"date\":\"2026-03-03T16:12:06-06:00\",\"videoType\":1,\"videoId\":\"EgWIbQyogYM\",\"type\":5,\"typeId\":92608,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":92608,\"name\":\"Landscape Photography\"}; WH.Layout.set({breadcrumb: [0, 3, 18, -655]}); //]]> // Links Landscape Photography Take enough photos of your neighborhood to inspire Corlen Hordralin . &nbsp; Locations Photographed &nbsp;( 1 ) &nbsp; Taken Landscape Photo &nbsp;( 5 ) &nbsp; Photo Taken &nbsp;( 1 ) &nbsp; Photo Taken &nbsp;( 1 ) &nbsp; Photo Taken &nbsp;( 1 ) &nbsp; Photo Taken &nbsp;( 1 ) &nbsp; Photo Taken &nbsp;( 1 ) &nbsp; Photo Taken &nbsp;( 1 ) &nbsp; Photo Taken &nbsp;( 1 ) &nbsp; Photo Taken &nbsp;( 1 )', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (92647, 0, 0, 'A low-level character cannot enter Shadowlands. Having received this quest in the dungeon, I cannot complete it. This is unbelievably lame but, alas, somewhat expected from nowadays-Blizzard. Last bosses that give loot from the chest, not from their corpse, do not count towards 5 dungeons. This is lame as well.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (92845, 0, 0, 'Fancy yourself a Brawlpub contender do you, &lt;class&gt;? They don\'t let just anyone in there, you know. Certainly not without an invitation. That said... just between you and me, if you know where to look and you\'ve the means they say anyone can have their moment in the spotlight these days.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (93384, 0, 0, 'I found the quest flying around in a book at /way #2393 41.53, 61.70 Delve Quest - Collegiate Calamity Was level 87 and missed the very first delve quest, so getting the presumed follow up is nice', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (93507, 0, 0, 'Upon completion of this quest you will gain: WH.Wow.Quest.setupScalingRewards({\"minLevel\":90,\"maxLevel\":90,\"xp\":{\"multiplier\":1,\"levels\":{\"90\":13690}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":1,\"levels\":{\"90\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(93507)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(93507))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (93647, 0, 0, 'Was flying around in Founder\'s Point and failed to find anything to harvest... after a while I realized that you will only see harvest targets in the world outside of Founder\'s Point (doh!)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (93792, 0, 0, 'De loa are quite generous indeed.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (93929, 0, 0, 'Tome has no quest marker tracking, it is outside the auction house. The satchel is also broken and will give nothing', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (93970, 0, 0, 'Please do not drop the sample.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (93997, 0, 0, 'Vidious is moving to claim Slayer\'s Rise, sending his proxies to occupy the Void Posts. I shall not be outmaneuvered. Seize full control of each of the Void Posts and eliminate any of Vidious\'s forces that try to stop you.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (93999, 0, 0, '3 tips, not sure which exactly worked for me.. after multiple attempts, finally got it working. 1. Wait until it is fully 100% captured. It doesn\'t necessarily need to start at -100% though. 2. Don\'t be mounted (I\'ve seen druids in flight form be able to do it though) 3. I went out of and back into warmode by talking to Ziadan at 34.83, 80.61 (This one might not be needed, but better safe than sorry)', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (94210, 0, 0, 'Have you met all the local vendors? They have some great furnishings available.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (94361, 0, 0, 'Temperance, acolyte. There is still more abundance to be collected yet.', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (94379, 0, 0, 'Did you get your house upgraded?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (94408, 0, 0, 'Are you here to deliver their contracts?', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (94432, 0, 0, 'If you\'re having trouble finding a piece of Veteran equipment, try completing a Heroic dungeon or a challenging weekly activity in Eversong, Zul\'Aman, Harandar, or Voidstorm. You can find more powerful gear this way!', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (94455, 0, 0, 'Previous: My First Home Next, if you choose the Decor Tutorial: Welcome Home var lv_screenshots = [{\"id\":1252811,\"user\":\"Rantsi\",\"date\":\"2025-11-19T19:00:56-06:00\",\"width\":1600,\"height\":900,\"type\":5,\"typeId\":94455,\"imageType\":2,\"staffOnly\":false,\"sticky\":1}]; var lv_videos = [{\"id\":394311,\"user\":\"gtulgar1903\",\"date\":\"2025-12-04T12:33:24-06:00\",\"videoType\":1,\"videoId\":\"Cf0zf5byHx0\",\"type\":5,\"typeId\":94455,\"url\":null},{\"id\":403915,\"user\":\"AQL1\",\"date\":\"2026-02-18T14:47:27-06:00\",\"videoType\":1,\"videoId\":\"h55vCvpg5vQ\",\"type\":5,\"typeId\":94455,\"url\":null,\"sticky\":1}]; var g_pageInfo = {\"type\":5,\"typeId\":94455,\"name\":\"Home at Last\"}; WH.Layout.set({breadcrumb: [0, 3, 19, -655]}); //]]> // Links Home at Last Approach your front door and enter your new house. &nbsp; Enter your house via the front door &nbsp;( 1 )', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (94581, 0, 0, 'Upon completion of this quest you will gain: WH.Wow.Quest.setupScalingRewards({\"minLevel\":90,\"maxLevel\":90,\"xp\":{\"multiplier\":1,\"levels\":{\"90\":13690}},\"coin\":{\"rewardAtCap\":0,\"multiplier\":1,\"levels\":{\"90\":0}}}); See if you\'ve already completed this by typing: /run print(C_QuestLog.IsQuestFlaggedCompleted(94581)) WH.clickToCopy(document.currentScript.parentNode, \"\\/run print(C_QuestLog.IsQuestFlaggedCompleted(94581))\"); $(\'.db-page-collection-tracker-cta\').append(WH.Tools.createWowheadClientCta());', 0);
INSERT IGNORE INTO `quest_request_items` (`ID`, `EmoteOnComplete`, `EmoteOnIncomplete`, `CompletionText`, `VerifiedBuild`) VALUES (95245, 0, 0, 'So I have been able to do all of these except Legend of the Haranir. I cant even get it started. Which NPC do I start it with and how can I find it?', 0);
